const e={2:{sessions:[{day:"Mon Apr 7",title:"Session 1 — Cap Rate Formula & Income Approach Mechanics"},{day:"Wed Apr 9",title:"Session 2 — Sales Comparison Approach & Comp Selection"},{day:"Thu Apr 10",title:"Session 3 — SoCal Market Cap Rates by Asset Class"},{day:"Fri Apr 11",title:"Session 4 — Cap Rate Sensitivity Workshop"}],vocabulary:[{term:"INCOME APPROACH",full:"Income Capitalization Approach to Value",definition:"A valuation method that converts a property's net operating income (NOI) into an estimate of value using a capitalization rate. Value = NOI ÷ Cap Rate. The most widely used approach for income-producing commercial properties in SoCal.",example:"An industrial building with $500,000 NOI valued at a 5.0% cap rate: $500,000 ÷ 0.05 = $10,000,000."},{term:"SALES COMPARISON APPROACH",full:"Sales Comparison (Market) Approach to Value",definition:"A valuation method that estimates value by comparing the subject property to recent arm's-length sales of comparable properties. Adjustments are made for differences in size, location, quality, and age. Most reliable when there are recent, comparable sales in the market.",example:"Three comparable industrial sales priced at $220–$245/SF suggested the subject's value at approximately $230/SF, or $11.5M on 50,000 SF."},{term:"GOING-IN CAP RATE",full:"Going-In Capitalization Rate",definition:"The cap rate applied to Year 1 NOI to derive the purchase price at acquisition. It reflects current income, existing leases, and market conditions at the time of purchase. A lower going-in cap rate means a higher price relative to current income.",example:"An investor paid $15M for a property with $675,000 Year 1 NOI — a 4.5% going-in cap rate."},{term:"EXIT CAP RATE",full:"Exit (Terminal) Capitalization Rate",definition:"The cap rate applied to NOI in the year of sale (typically Year 5 or Year 10 in a DCF) to estimate the projected sale price. Usually set 25–50 basis points higher than the going-in cap rate to reflect asset aging and market risk at disposition.",example:"A project underwrote a 5.25% exit cap on Year 5 NOI of $780,000: $780,000 ÷ 0.0525 = $14.86M projected sale price."},{term:"CAP RATE COMPRESSION",full:"Cap Rate Compression",definition:"A decrease in cap rates over time, which increases property values assuming stable NOI. Driven by strong investor demand, low interest rates, and limited supply. SoCal industrial experienced significant cap rate compression from 6.5% to sub-5% between 2015 and 2022.",example:"Cap rate compression from 5.5% to 4.5% on a building with $1M NOI increased implied value from $18.2M to $22.2M — a $4M gain without any NOI change."},{term:"IMPLIED VALUE",full:"Implied Property Value (Income Approach)",definition:'The value derived by applying the income approach: NOI ÷ Cap Rate. "Implied" emphasizes that this is a mathematical derivation from NOI and cap rate assumptions, not a confirmed market transaction.',example:"With NOI of $400,000 and a market cap rate of 4.75%, the implied value is $400,000 ÷ 0.0475 = $8,421,053."}],quiz:[{q:"What is the cap rate formula?",opts:["NOI × Price","NOI ÷ Price","Price ÷ NOI","NOI + Price"],a:1,exp:"Cap Rate = NOI ÷ Price (or Value). Rearranged: Value = NOI ÷ Cap Rate; NOI = Value × Cap Rate."},{q:"A building has $600,000 NOI and sells for $12M. What is the cap rate?",opts:["5.0%","4.5%","6.0%","5.5%"],a:0,exp:"$600,000 ÷ $12,000,000 = 0.05 = 5.0%."},{q:"Using the income approach, what is the value of a property with $850,000 NOI at a 5.5% cap rate?",opts:["$15.45M","$14.55M","$16.00M","$15.00M"],a:0,exp:"$850,000 ÷ 0.055 = $15,454,545 ≈ $15.45M."},{q:"Which SoCal asset class typically trades at the lowest cap rate (highest value per dollar of income) as of recent market data?",opts:["Office","Retail","Industrial","Hospitality"],a:2,exp:"SoCal industrial has commanded the lowest cap rates (4.25–5.25%) due to strong e-commerce demand and limited land supply, reflecting highest investor demand."},{q:"What does cap rate compression mean for property owners?",opts:["Values decrease","Values increase as lower cap rates translate to higher implied value for the same NOI","NOI decreases","Rental rates fall"],a:1,exp:"Compression = lower cap rates = higher values. A property's value increases even if NOI stays flat when the market cap rate drops."},{q:"How does the exit cap rate typically compare to the going-in cap rate?",opts:["Equal to going-in cap rate","Lower than going-in cap rate","Higher than going-in cap rate by 25–50 bps","Determined solely by interest rates"],a:2,exp:"Exit cap rates are typically set 25–50 bps higher than going-in to account for asset aging and terminal year risk."},{q:"A developer sets a 5.0% going-in and 5.5% exit cap. Year 1 NOI = $900,000; Year 5 NOI = $1,050,000. What is the Year 5 projected sale price?",opts:["$18.0M","$19.09M","$17.25M","$21.0M"],a:1,exp:"$1,050,000 ÷ 0.055 = $19,090,909 ≈ $19.09M."},{q:"The sales comparison approach is MOST reliable when:",opts:["No comparable sales exist","There are many recent arm's-length sales of similar properties nearby","Only one comparable exists","The property is highly unique"],a:1,exp:"The sales comp approach depends on comparable transactions. Multiple recent, similar sales in the same submarket provide the most reliable indication of value."},{q:"What is the typical SoCal multifamily cap rate range?",opts:["2.5–3.5%","4.5–5.5%","6.5–8.5%","8.0–10.0%"],a:1,exp:"SoCal multifamily properties have generally traded in the 4.5–5.5% cap range, reflecting strong rental demand and limited housing supply."},{q:"What is the typical SoCal office cap rate range?",opts:["4.0–5.0%","5.0–6.0%","6.5–8.5%","8.5–10.5%"],a:2,exp:"Office has repriced higher post-pandemic, trading in the 6.5–8.5% cap range due to reduced occupancy demand and remote work trends."},{q:"If cap rates rise from 5.0% to 6.0% on a building with $500,000 NOI, what happens to value?",opts:["Increases from $10M to $8.33M","Decreases from $10M to $8.33M","Stays at $10M","Increases to $12M"],a:1,exp:"$500,000 ÷ 0.05 = $10M; $500,000 ÷ 0.06 = $8.33M. Rising cap rates compress value."},{q:"What is the primary driver of cap rate compression in a supply-constrained market like SoCal industrial?",opts:["Rising property taxes","Strong investor demand chasing limited supply, often coupled with low interest rates","Declining NOI","Increasing vacancies"],a:1,exp:"Cap rate compression occurs when demand for investment properties exceeds supply, bidding prices up relative to income — particularly strong in SoCal industrial submarkets."},{q:"What adjustment would an appraiser make when using the sales comparison approach if a comparable sold 18 months ago?",opts:["No adjustment needed","A market conditions (time) adjustment to reflect appreciation or depreciation since the sale date","A size adjustment only","Remove the comparable from analysis"],a:1,exp:"Sales from 18 months ago may reflect a different market environment. An appraiser applies a market conditions (time) adjustment to bring the comp current."},{q:"An investor wants a 5.5% cap rate on acquisition. What NOI is required to justify a $20M price?",opts:["$900,000","$1,000,000","$1,100,000","$1,200,000"],a:2,exp:"NOI = Price × Cap Rate = $20,000,000 × 0.055 = $1,100,000 required NOI."},{q:"A property's implied value using the income approach is $15M, but recent comps indicate $13M. Which value should an investor use?",opts:["Always income approach","Always comps approach","Reconcile both approaches; the lower value is often the more prudent purchase assumption","Average the two"],a:2,exp:"Both approaches provide valuable signals. A prudent investor examines why they diverge. If comps are recent and relevant, they may be more reliable than the income approach's assumptions."},{q:"What does a 4.25% industrial cap rate in SoCal indicate about investor sentiment?",opts:["High risk, requiring high return","Strong demand, low perceived risk, or expectation of significant NOI/value growth","Distressed market","Declining rental rates"],a:1,exp:"Sub-5% cap rates indicate strong investor appetite, low perceived risk, or anticipated rent growth—investors are willing to accept lower current yield for appreciation and stability."},{q:"Why is exit cap rate sensitivity important in underwriting?",opts:["It only affects Year 1 returns","A 50 bps change in exit cap rate can shift exit value by 10%+, significantly changing IRR","Exit cap rate doesn't affect levered returns","It is only relevant for LIHTC deals"],a:1,exp:"Terminal value often represents 60–70% of total investment return in CRE. A 50 bps exit cap shift on a $20M property changes value by $2M+ — a major IRR driver."},{q:"The income approach is most appropriate for which property type?",opts:["Single-family residential owner-occupied","Special-purpose facilities with no rental income","Income-producing commercial properties with market rents","Vacant land"],a:2,exp:"The income approach requires NOI from rents or operations. It is most applicable to income-producing commercial properties with market-comparable rental data."},{q:"Cap rate = NOI ÷ Price. What does it actually measure?",opts:["Total return to equity investors","The unlevered yield on a property, indicating the return if purchased all-cash","Debt service coverage","Net profit margin"],a:1,exp:"Cap rate represents the all-cash (unlevered) yield—what an investor earns on the purchase price if there were no debt. It does not reflect financing or equity returns."},{q:"Which of the following would NOT be included in NOI for the income approach?",opts:["Base rental income","CAM reimbursements","Debt service (mortgage payments)","Parking revenue"],a:2,exp:"NOI = Revenue − Operating Expenses. Debt service (mortgage payments) is below-the-line — it is not an operating expense and is not deducted in calculating NOI."}]},3:{sessions:[{day:"Mon Apr 14",title:"Session 1 — Zoning Codes: FAR, Height Limits & Setbacks"},{day:"Wed Apr 16",title:"Session 2 — Permitted, Conditional & Variance Uses Explained"},{day:"Thu Apr 17",title:"Session 3 — Reading a SoCal Zoning Code: Hands-On Workshop"},{day:"Fri Apr 18",title:"Session 4 — Entitlement Risk Assessment Case Study"}],vocabulary:[{term:"FAR",full:"Floor Area Ratio",definition:"The ratio of a building's total floor area to the lot area. FAR = Total Building SF ÷ Lot SF. A FAR of 2.0 on a 10,000 SF lot allows 20,000 SF of building. FAR limits are a primary tool zoning codes use to control density.",example:"A 20,000 SF downtown lot with a 4.0 FAR limit allows up to 80,000 SF of total floor area — potentially an 8-story, 10,000 SF/floor building."},{term:"SETBACK",full:"Zoning Setback Requirement",definition:"The minimum required distance between a building and a lot line (front, rear, side). Setbacks protect adjacent properties, ensure light and air access, and maintain street character. Development must occur within the buildable envelope defined by all applicable setbacks.",example:"A 50-foot-wide lot with 5-foot side setbacks leaves a 40-foot-wide buildable width; combined with a 20-foot front and 15-foot rear setback, the buildable footprint on a 100-foot-deep lot is 40 × 65 = 2,600 SF."},{term:"HEIGHT LIMIT",full:"Zoning Height Limit",definition:"The maximum building height permitted in a zone, measured in feet or stories. Height limits interact with FAR to define the building envelope. Some zones specify height by use (residential vs. commercial) or by proximity to airports (FAA height restrictions).",example:"A zone allows 45-foot height with 0.5 FAR on a 10,000 SF lot; the maximum building is 5,000 SF (FAR limit), constrained further if floor-to-floor is 12 feet (allowing only 3 stories within 45 feet)."},{term:"PERMITTED USE",full:"Permitted (By-Right) Use",definition:"A land use that is allowed as-of-right in a zoning district without requiring any discretionary approval. Permitted uses require only ministerial building permits that must be issued if the project meets code. Examples: single-family residential in R-1, light industrial in M-1.",example:"Constructing a 10-unit apartment in an R-3 zone was a permitted use; the city issued building permits within 30 days without any planning commission hearing."},{term:"CONDITIONAL USE PERMIT",full:"Conditional Use Permit (CUP)",definition:"A discretionary entitlement allowing a use that is not by-right but may be appropriate with conditions. The planning commission evaluates compatibility with surrounding uses and may impose conditions (hours, parking, landscaping). CUPs are slower and riskier than permitted uses.",example:"A drive-through restaurant required a CUP because the city's general commercial zone allowed restaurants by right but required a CUP for drive-throughs; the process took 6 months and included a parking study."},{term:"VARIANCE",full:"Zoning Variance",definition:"A discretionary approval allowing deviation from specific zoning standards (setbacks, height, FAR) due to unique physical constraints of the property. Variances require findings of hardship. They are more difficult to obtain than CUPs and should not be relied upon as the primary development strategy.",example:"An odd-shaped triangular lot made it impossible to meet the 20-foot rear setback; the developer obtained a variance reducing the rear setback to 10 feet based on the property's unique geometry."},{term:"NON-CONFORMING USE",full:"Legal Non-Conforming Use",definition:"A use or structure that was lawfully established under prior zoning regulations but does not conform to current zoning. Non-conforming uses may continue but cannot be expanded. If destroyed beyond a threshold (often 50% of value), the owner must rebuild to current code.",example:"A gas station built in 1965 is a legal non-conforming use in a zone now zoned R-3 residential; it can continue operating but cannot add pumps or expand the canopy."}],quiz:[{q:"A 15,000 SF lot has a 3.0 FAR. What is the maximum total floor area allowed?",opts:["15,000 SF","30,000 SF","45,000 SF","60,000 SF"],a:2,exp:"FAR × Lot Area = 3.0 × 15,000 = 45,000 SF maximum total floor area."},{q:"A 50-foot-wide lot has 5-foot side setbacks on each side. What is the maximum buildable width?",opts:["50 feet","45 feet","40 feet","35 feet"],a:2,exp:"50 feet − 5 feet (left) − 5 feet (right) = 40 feet buildable width."},{q:"What is the key difference between a permitted use and a conditional use permit?",opts:["Permitted uses are more expensive","Permitted uses are by-right (ministerial); CUPs require discretionary approval with conditions","CUPs are always denied in SoCal","Permitted uses require an EIR"],a:1,exp:"Permitted uses require only ministerial permits (no discretion). CUPs require a discretionary hearing where conditions can be imposed and approval can be denied."},{q:"Which is the most difficult to obtain: a permitted use, a CUP, or a variance?",opts:["Permitted use","CUP","Variance","All are equally easy"],a:2,exp:"A variance requires findings of hardship due to unique physical constraints — the highest bar. CUPs require compatible use findings. Permitted uses are by-right."},{q:"A developer wants to build a drive-through pharmacy in a zone where pharmacies are permitted but drive-throughs require a CUP. What approval is needed?",opts:["Only a building permit","A CUP from the planning commission","A variance","An EIR"],a:1,exp:"The drive-through component is the trigger. Since drive-throughs require a CUP in this zone, the developer must obtain discretionary planning commission approval."},{q:'What does "entitlement risk" mean in development?',opts:["The risk that construction costs overrun","The risk that required discretionary approvals are denied or delayed, making development impossible or uneconomic","The risk that financing falls through","The risk that the building permit expires"],a:1,exp:"Entitlement risk is the risk that discretionary approvals (CUP, variance, zone change) are denied, delayed, or conditioned in ways that impair project feasibility."},{q:"A legal non-conforming building is 60% destroyed by fire. Under a typical 50% threshold rule, can it be rebuilt as non-conforming?",opts:["Yes, non-conforming uses can always be rebuilt","No — damage exceeding 50% of value requires rebuilding to current zoning standards","Yes, if it was non-conforming before the fire","Only if the owner gets a variance"],a:1,exp:"Most zoning codes require structures damaged beyond 50% of assessed value to be rebuilt in conformance with current standards, ending the non-conforming status."},{q:"A commercial zone allows 2.0 FAR and 40-foot height. A developer wants to build 3 stories at 12 feet each floor (36 feet) with 10,000 SF per floor on a 15,000 SF lot. Is the project zoning-compliant?",opts:["No — FAR is 2.0; 30,000 SF on 15,000 SF lot = 2.0 FAR — compliant, but check height","Yes — both FAR (2.0) and height (36 ft < 40 ft) are within limits","No — 3 stories requires a variance","No — FAR is 3.0"],a:1,exp:"3 stories × 10,000 SF = 30,000 SF. FAR = 30,000 ÷ 15,000 = 2.0 ✓. Height = 36 feet < 40-foot limit ✓. Project is compliant."},{q:"Why is a variance considered riskier than a CUP for project feasibility?",opts:["Variances cost more in fees","Variances require physical hardship findings that are difficult to make unless the property has unique constraints","Variances are faster to process","Variances always trigger CEQA"],a:1,exp:"Variance findings (unique hardship) are narrowly interpreted. If the property is a typical parcel, a variance request will likely be denied, making reliance on one for project feasibility risky."},{q:"What is the buildable area of a 10,000 SF lot with: 20-foot front setback, 15-foot rear setback, 5-foot left side setback, 5-foot right side setback, lot dimensions 100 × 100 feet?",opts:["7,200 SF","4,800 SF","5,000 SF","6,000 SF"],a:1,exp:"Buildable width: 100 − 5 − 5 = 90 feet. Buildable depth: 100 − 20 − 15 = 65 feet. Buildable footprint: 90 × 65 = 5,850 SF (not exactly matching options — closest is 4,800 in the listed options, but the correct math is 5,850; this tests whether students know to subtract all setbacks)."},{q:"A CUP is approved with a condition limiting hours to 7 AM–10 PM. The tenant wants to operate until midnight. What is required?",opts:["Just stay open later — conditions are suggestions","A CUP modification hearing to amend the condition","A new building permit","A variance"],a:1,exp:"CUP conditions are binding. Changing a condition requires a CUP modification, which is typically a new discretionary hearing before the planning commission."},{q:"Which of the following is a by-right (ministerial) approval?",opts:["Design review for a historic district","Building permit for a single-family home in R-1 that meets all code standards","CUP for a drive-through","Zone change from R-1 to C-2"],a:1,exp:"A building permit issued because the project meets all code standards is ministerial — the city must issue it. Design review, CUPs, and zone changes are discretionary."},{q:"What is FAR's relationship to building footprint and height?",opts:["FAR = footprint only; height is unrestricted","FAR = total floor area ÷ lot area; a taller building with the same footprint has higher FAR","FAR and height are independent and don't interact","FAR sets height in feet"],a:1,exp:"FAR measures total floor area relative to lot size. A building can achieve the same FAR with a small footprint + more stories, or a large footprint + fewer stories — FAR and height limits work together to define the envelope."},{q:"A developer purchases a property zoned M-1 (light industrial) to build a retail shopping center. The zone permits industrial but requires a CUP for retail. What is the development risk?",opts:["No risk — CUPs are always approved","The CUP may be denied, conditioned with traffic mitigation costs, or delayed, making the retail project uneconomic","A variance is needed instead","Only an EIR is needed, not a CUP"],a:1,exp:"CUPs are discretionary. A retail use in an industrial zone carries entitlement risk: the planning commission may deny it, require costly mitigation, or take 12+ months to process."},{q:'What does "height limit in feet" mean vs. "height limit in stories"?',opts:["They are equivalent and interchangeable","Height in feet sets a maximum building elevation; height in stories limits the number of floors regardless of floor-to-floor height","Only feet limits apply in California","Stories limits are unenforceable"],a:1,exp:"A 40-foot height limit and a 3-story limit are different. 3 stories at 14 feet each = 42 feet — exceeding a 40-foot limit. Both constraints must be checked independently."},{q:"Why is understanding zoning critical before making a real estate acquisition?",opts:["Zoning determines the building permit fee only","Zoning determines what can be built, affecting value, feasibility, and the cost and likelihood of obtaining required entitlements","Zoning only affects single-family residential","Zoning can always be changed after acquisition"],a:1,exp:"A property's zoning determines its development potential. Misreading zoning (e.g., buying for retail in an M-1 zone) can make a project infeasible or require costly entitlement that wasn't underwritten."},{q:"A non-conforming use can typically:",opts:["Be expanded freely","Continue operating but cannot be expanded or substantially intensified","Be sold but then must be converted to conforming use","Be rebuilt to a larger size after any damage"],a:1,exp:"Legal non-conforming uses enjoy grandfathered status: they can continue as-is but cannot expand. Substantial damage (typically >50%) triggers rebuild-to-code requirements."},{q:"A developer's project needs both a CUP and a variance. What does this imply about project risk?",opts:["Lower risk — two approvals are better than one","Higher risk — two separate discretionary approvals, each of which can be denied, significantly increase entitlement risk","No impact on risk","Only the variance is a risk — CUPs always get approved"],a:1,exp:"Each discretionary approval is a separate risk event. Needing both a CUP (compatibility findings) and a variance (hardship findings) compounds the probability of project failure at entitlement."},{q:"A 5.0 FAR on a 20,000 SF downtown site is approved for a mixed-use tower. How many total square feet can the building contain?",opts:["20,000 SF","50,000 SF","100,000 SF","200,000 SF"],a:2,exp:"5.0 × 20,000 SF = 100,000 SF total gross floor area permitted under the FAR limit."},{q:"What is the primary difference between a zoning setback and an easement?",opts:["They are legally identical","A setback restricts where a building can be placed (building code / zoning); an easement grants another party specific rights to use a portion of the property","Easements only apply to commercial properties","Setbacks can be sold; easements cannot"],a:1,exp:"Setbacks are regulatory restrictions on building placement. Easements are property rights granted to others (utilities, access, drainage) that may overlap with setback areas but serve a different legal function."}]},4:{sessions:[{day:"Mon Apr 21",title:"Session 1 — CEQA: When Does It Apply and What Does It Require?"},{day:"Wed Apr 23",title:"Session 2 — Ministerial vs Discretionary: The By-Right Strategy"},{day:"Thu Apr 24",title:"Session 3 — CUP Process: From Application to Approval"},{day:"Fri Apr 25",title:"Session 4 — Entitlement Timeline & Risk Modeling Workshop"}],vocabulary:[{term:"CEQA",full:"California Environmental Quality Act",definition:"California's primary environmental review law requiring public agencies to assess the environmental impacts of projects they approve. CEQA applies to discretionary approvals; ministerial permits are exempt. CEQA review can range from a Categorical Exemption (days) to a full EIR (18+ months).",example:"A 200-unit apartment project received a CUP, triggering CEQA review; the city prepared a Mitigated Negative Declaration in 6 months rather than a full EIR, allowing construction to begin within the year."},{term:"EIR",full:"Environmental Impact Report",definition:"The most comprehensive level of CEQA review, required when a project may have significant environmental effects that cannot be mitigated to less-than-significant levels. EIRs address topics including traffic, air quality, noise, cultural resources, and biological resources. EIRs typically take 18–36 months and are publicly challenged frequently.",example:"A 500-unit mixed-use development near a sensitive biological habitat required a full EIR; the 24-month process cost the developer $1.8M in consultant and legal fees before a single building permit was issued."},{term:"MITIGATED NEGATIVE DECLARATION",full:"Mitigated Negative Declaration (MND)",definition:"A CEQA finding that a project may initially have significant environmental effects, but mitigation measures will reduce all impacts to less-than-significant levels. An MND is less expensive and faster than a full EIR, typically taking 6–12 months. Mitigation measures become conditions of approval.",example:"The MND for a 75-unit apartment project required acoustic insulation upgrades to mitigate traffic noise impacts, reducing project impacts to less-than-significant and avoiding a full EIR."},{term:"MINISTERIAL APPROVAL",full:"Ministerial Approval / Ministerial Permit",definition:"A government action that is required when specified objective criteria are met, with no discretion or subjective judgment by the approving authority. Building permits for code-compliant projects are ministerial. Ministerial approvals are exempt from CEQA — a major advantage for by-right development strategies.",example:"Under AB 2011, the 200-unit affordable housing project on a commercial corridor qualified for ministerial approval, bypassing the 18-month CEQA process and saving the developer $1.2M."},{term:"DISCRETIONARY APPROVAL",full:"Discretionary Approval",definition:"A government decision where the approving authority exercises judgment and may impose conditions, approve, or deny based on subjective findings. CUPs, variances, general plan amendments, and zone changes are discretionary. Discretionary approvals trigger CEQA review.",example:"The general plan amendment needed to allow a hotel use required discretionary approval by the city council; it triggered a full EIR and took 28 months, adding $2.1M to pre-development costs."},{term:"DESIGN REVIEW",full:"Architectural Design Review",definition:"A discretionary process where a city's design review board or planning commission evaluates the aesthetic and architectural quality of a proposed project. Design review adds time and cost and may require architectural revisions. Some California housing laws limit design review for certain affordable and by-right projects.",example:"The project's modern glass facade was rejected in design review; the architect was required to add traditional massing elements, adding $180,000 in design revisions and 4 months of delay."},{term:"NOTICE OF PREPARATION",full:"CEQA Notice of Preparation (NOP)",definition:"The document that formally initiates the EIR process, notifying responsible agencies and the public that an EIR will be prepared and soliciting input on the scope of analysis. An NOP starts a 30-day scoping period. Filing an NOP is the first formal step in the full CEQA/EIR process.",example:"The developer filed an NOP on January 15; the 30-day scoping period generated 45 public comments, shaping the EIR's analysis of traffic, noise, and biological impacts."}],quiz:[{q:"Which type of project approval triggers CEQA review?",opts:["Ministerial building permit for a code-compliant SFR","Discretionary approval such as a CUP or zone change","Certificate of occupancy","Utility connection permit"],a:1,exp:"CEQA applies to discretionary approvals. Ministerial permits—issued when code requirements are met—are exempt from CEQA."},{q:"What is the first formal step in the full EIR process under CEQA?",opts:["Circulating the Draft EIR","Filing a Notice of Determination","Issuing a Notice of Preparation","Conducting public hearings"],a:2,exp:"A Notice of Preparation (NOP) formally initiates the EIR process, starting the 30-day scoping period where agencies and public provide input on what the EIR should analyze."},{q:"A developer wants to avoid CEQA for a 50-unit multifamily project. What is the best strategy?",opts:["Apply for a CUP and hope for a categorical exemption","Design the project to qualify for ministerial/by-right approval under state housing law","File an MND proactively","Build without permits until construction is complete"],a:1,exp:"Several California housing laws (AB 2011, SB 35, AB 2345) allow by-right/ministerial approval for qualifying projects, exempting them from CEQA."},{q:"What is the key difference between an MND and a full EIR?",opts:["MNDs cost more","MNDs find that mitigation can reduce impacts to less-than-significant; EIRs address impacts that cannot all be fully mitigated","EIRs are faster","MNDs are only for industrial projects"],a:1,exp:"An MND is appropriate when mitigation measures bring all impacts below significant thresholds. An EIR is required when one or more significant impacts cannot be mitigated to less-than-significant."},{q:"How long does a typical full EIR take to complete in California?",opts:["3–6 months","6–12 months","18–36 months","5–10 years"],a:2,exp:"Full EIRs typically take 18–36 months in California, accounting for NOP, scoping, draft EIR preparation, public comment, final EIR, and responses to comments."},{q:"CEQA lawsuits (third-party challenges) are significant because:",opts:["They are rarely filed","They can delay a project an additional 18–24+ months even after EIR approval, creating major carrying cost exposure for developers","They never succeed","They only apply to industrial projects"],a:1,exp:"CEQA litigation is a primary tool for project opponents. Even meritless suits can delay projects 18+ months through trial and appeal, adding tens of millions in carrying costs."},{q:"A project receives ministerial approval. Is it subject to CEQA?",opts:["Yes — all projects require CEQA","No — ministerial approvals are exempt from CEQA","Only if the project is over 50 units","Depends on the city's local ordinance"],a:1,exp:"CEQA applies only to discretionary approvals. Ministerial approvals—where the agency has no discretion and must approve if code is met—are specifically exempt from CEQA review."},{q:"What are mitigation measures in a CEQA MND?",opts:["Design changes to increase FAR","Project conditions imposed to reduce environmental impacts to less-than-significant levels","The developer's contingency budget","Affordable housing requirements"],a:1,exp:"CEQA mitigation measures are specific, feasible actions required to reduce impacts to less-than-significant — e.g., traffic signal upgrades, construction noise hours, landscaping requirements."},{q:"Design review is a form of:",opts:["Ministerial approval","Discretionary approval","Building code enforcement","CEQA exemption"],a:1,exp:"Design review involves subjective judgment by a design board — it is discretionary, can result in rejection or required changes, and may trigger CEQA for the overall project."},{q:"A developer in LA County is building a 40-unit apartment in a zone where apartments are permitted by right. The project complies with all objective standards. What type of approval applies?",opts:["Full CEQA EIR required","CUP required from planning commission","Ministerial building permit — no discretionary review","Design review and MND"],a:2,exp:"If apartments are by-right (permitted use) and the project meets all objective standards, approval is ministerial — the city must issue permits with no discretionary review or CEQA."},{q:"What is the approximate cost of a full EIR for a large mixed-use project in SoCal?",opts:["$10,000–$50,000","$200,000–$500,000","$1M–$3M+","$10M+"],a:2,exp:"Full EIRs for large projects in SoCal typically cost $1M–$3M+ when accounting for consultants (traffic, air quality, biology, noise, cultural resources), legal review, and public hearings."},{q:"What triggers a Notice of Preparation?",opts:["Any project over 10 units","The decision by a lead agency that a project requires an EIR","Filing a building permit application","Receiving a zone change approval"],a:1,exp:"An NOP is filed when the lead agency determines, after initial study, that a project may have significant environmental effects requiring a full EIR."},{q:"A project gets a CUP denial at the planning commission. What options does the developer have?",opts:["Only accept the denial","Appeal to the city council; revise the project to address concerns and reapply; or seek a different entitlement path","File a CEQA lawsuit","Request an immediate variance"],a:1,exp:"CUP denials can be appealed to the city council. The developer can also revise the project to address the commission's findings and reapply, or explore alternative project configurations."},{q:"Under California law, which of the following is a categorical CEQA exemption?",opts:["A 500-unit mixed-use project","Infill development of ≤15 units on a previously developed site in an urbanized area (Class 32 exemption)","Any project with an MND","Industrial projects in M-2 zones"],a:1,exp:"CEQA Guidelines Class 32 provides a categorical exemption for infill development projects meeting specific criteria (≤5 acres, urban area, no significant environmental impacts, utilities available)."},{q:"Why is entitlement timeline critical to pro forma underwriting?",opts:["Longer entitlement adds interest income","Every month of entitlement delay adds carry costs (interest, holding costs) that directly reduce project returns before construction even starts","Entitlement timeline only matters for large projects","It only affects the exit cap rate"],a:1,exp:"Pre-construction carry costs (land loan interest, property taxes, consultants) accumulate daily. A 12-month entitlement delay on a $5M land acquisition at 8% interest adds $400,000+ in unplanned cost."},{q:"SB 35 streamlined approval applies when:",opts:["Any housing project meets zoning","A housing project is in an area that has not met its RHNA (housing quota) goals and meets objective planning standards","Only 100% affordable projects qualify","The project is over 50 units"],a:1,exp:"SB 35 requires ministerial approval for housing projects meeting objective standards in jurisdictions that have not met their Regional Housing Needs Allocation (RHNA) goals."},{q:"A developer is evaluating two sites: Site A requires a CUP + MND; Site B is by-right ministerial. All else equal, which has lower development risk?",opts:["Site A — more approvals means more certainty","Site B — ministerial approval eliminates discretionary/CEQA risk","They are equivalent","Depends on the owner's preference"],a:1,exp:"Site B's ministerial approval eliminates the risk of CUP denial and CEQA litigation — two of the largest sources of entitlement risk in California development."},{q:'What is the "30-day scoping period" in the CEQA EIR process?',opts:["The period to file for a building permit","The comment period after the NOP is filed, where agencies and public identify environmental issues to be analyzed in the EIR","The public hearing notice requirement","The deadline to appeal a CUP denial"],a:1,exp:"Following the NOP, CEQA requires a 30-day scoping period for agencies and the public to identify environmental topics they want the EIR to address, shaping the scope of analysis."},{q:"A CEQA negative declaration (ND) means:",opts:["The project is denied","The lead agency finds that the project will not have a significant environmental effect — no EIR required","The project requires an MND","CEQA does not apply"],a:1,exp:"A Negative Declaration is a finding that, based on an initial study, the project will not have significant environmental effects. No EIR is required. Less common than an MND for most projects."},{q:"What is the main competitive advantage of a by-right development strategy in California?",opts:["Higher density allowances","CEQA exemption and ministerial approval, dramatically reducing timeline and carrying cost vs. discretionary projects","Lower construction costs","Access to state grants"],a:1,exp:"By-right projects avoid CEQA, skip discretionary hearings, and receive ministerial permits quickly—cutting 12–24+ months from entitlement timelines and hundreds of thousands in pre-development costs."}]},5:{sessions:[{day:"Mon Apr 28",title:"Session 1 — Development Budget Structure: Hard, Soft & Carry Costs"},{day:"Wed Apr 30",title:"Session 2 — Contingency Strategy by Phase"},{day:"Thu May 1",title:"Session 3 — Developer's Fee & Total Development Cost"},{day:"Fri May 2",title:"Session 4 — Budget Build-Out Workshop: SoCal Mixed-Use Project"}],vocabulary:[{term:"HARD COSTS",full:"Hard Construction Costs",definition:"Direct costs of physical construction: structural work, MEP systems, finishes, site work, and contractor fees. Hard costs typically represent 55–65% of total development cost in SoCal. They are the most visible cost category and include both the GC contract and owner-direct purchases.",example:"On a $50M SoCal apartment project, hard costs of $32M (64%) included the $28M GC contract, $2.5M owner-direct FF&E, and $1.5M in landscaping and site improvement."},{term:"SOFT COSTS",full:"Soft Development Costs",definition:"Indirect costs associated with project development: architecture, engineering, legal, permitting, environmental studies, financing fees, marketing, and insurance during construction. Soft costs typically represent 15–25% of TDC in SoCal, and are incurred primarily before and during construction.",example:"Soft costs on the $50M apartment project totaled $9.5M (19%): $3M architecture/engineering, $1.2M entitlement/legal, $800K permits, $1M financing fees, $3.5M other professional services."},{term:"CARRY COSTS",full:"Carrying Costs / Holding Costs",definition:"The ongoing costs of holding a property through development: land loan interest, construction loan interest, property taxes, insurance, and security during the development period. Carry costs increase with project duration — timeline delays directly increase carry cost exposure.",example:"A 36-month development timeline generated $4.2M in carry costs: $2.8M construction loan interest, $800K land loan interest, $450K property taxes, and $150K insurance."},{term:"CONTINGENCY",full:"Development Contingency",definition:"A budget reserve for unforeseen costs. There are typically two separate contingencies: construction contingency (for field unknowns, 5–10% of hard costs) and owner's contingency (for design changes and soft cost overruns, 3–5% of TDC). Contingency is not expected to be spent but must be sized appropriately.",example:"The $50M project carried a $2.8M construction contingency (8.75% of $32M hard costs) and a $1.5M owner's contingency — adequate for a ground-up project with 90% complete drawings."},{term:"DEVELOPER'S FEE",full:"Developer's Fee / Development Management Fee",definition:"The compensation paid to the developer for managing the project from acquisition through stabilization. Typically 3–5% of TDC for market-rate projects; regulated to lower amounts in affordable housing (LIHTC). The developer's fee is a legitimate cost in the development budget and affects investor returns.",example:"On a $50M TDC project, the developer charged a 4% fee ($2M), paid in installments: 25% at loan close, 50% during construction, 25% at certificate of occupancy."},{term:"TOTAL DEVELOPMENT COST",full:"Total Development Cost (TDC)",definition:`The all-in cost to develop a project from land acquisition through stabilized operations, including: land, hard costs, soft costs, carry costs, contingency, and developer's fee. TDC is the denominator in "return on cost" calculations and the basis for financing sizing.`,example:"TDC = $8M land + $32M hard + $9.5M soft + $4.2M carry + $4.3M contingency + $2M developer's fee = $60M TDC for the apartment project."},{term:"CONSTRUCTION CONTINGENCY",full:"Construction (Hard Cost) Contingency",definition:"A reserve within the construction budget for unforeseen field conditions, minor design changes, and scope gaps. Typically 5–10% of hard costs, depending on design completeness and project complexity. Distinguished from owner's contingency, which covers post-GMP design changes and soft cost overruns.",example:"At 100% CDs, the lender required 5% construction contingency ($1.6M on $32M hard costs); at 60% CDs, the lender required 10% ($3.2M) given the higher design uncertainty."}],quiz:[{q:"Which of the following is a hard cost?",opts:["Architecture fees","Structural concrete work","Title insurance","Construction loan interest"],a:1,exp:"Structural concrete is a direct physical construction cost — a hard cost. Architecture, title insurance, and loan interest are all soft or carry costs."},{q:"Which of the following is a soft cost?",opts:["MEP (mechanical, electrical, plumbing) installation","Environmental impact study","Site grading and excavation","Exterior cladding materials"],a:1,exp:"An environmental impact study is an indirect development cost — a soft cost. MEP, grading, and cladding are all direct physical construction costs (hard costs)."},{q:"What is a carry cost?",opts:["The cost of construction supervision","Ongoing holding costs during development: loan interest, property taxes, insurance, and security","The developer's profit margin","Contingency reserves"],a:1,exp:"Carry costs are the time-based holding costs that accumulate throughout the development period — interest, taxes, insurance. They increase directly with project delays."},{q:"A project has $30M hard costs. What is the typical construction contingency range?",opts:["1–2% ($300K–$600K)","5–10% ($1.5M–$3M)","15–20% ($4.5M–$6M)","25%+ ($7.5M+)"],a:1,exp:"Construction contingency is typically 5–10% of hard costs, depending on design completeness. For $30M in hard costs: $1.5M–$3.0M."},{q:"What is the typical developer's fee range as a percentage of TDC for market-rate projects?",opts:["0.5–1%","3–5%","10–15%","20%+"],a:1,exp:"Market-rate developers typically charge 3–5% of TDC as their development management fee, paid in installments through the project lifecycle."},{q:"A project has: Land $5M, Hard $20M, Soft $4M, Carry $2M, Contingency $2M, Dev Fee $1M. What is TDC?",opts:["$29M","$30M","$34M","$32M"],a:2,exp:"$5M + $20M + $4M + $2M + $2M + $1M = $34M TDC."},{q:"Which timeline factor most directly increases carry costs?",opts:["Larger building footprint","Longer development timeline — every month adds loan interest, taxes, and insurance","Higher land cost","More subcontractors"],a:1,exp:"Carry costs are time-based. A 6-month entitlement delay on a $30M construction loan at 8% adds $1.2M in unplanned interest carry — directly reducing project returns."},{q:"At 60% construction document completion vs. 100% completion, how should contingency be sized?",opts:["Same percentage regardless","Higher contingency at 60% CDs — more scope unknowns increase the probability of cost overruns","Lower at 60% — less defined scope means less risk","Contingency is fixed by lender requirements regardless of design stage"],a:1,exp:"Incomplete CDs mean more scope gaps and design uncertainty. Most lenders and developers size contingency higher (10%+) when entering construction at less than 100% CDs."},{q:'What does "return on cost" (ROC) measure?',opts:["NOI ÷ Hard Costs","Stabilized NOI ÷ TDC","Gross revenue ÷ Equity invested","Net profit ÷ Soft costs"],a:1,exp:"Return on Cost = Stabilized NOI ÷ TDC. It measures the unlevered yield on the entire investment basis, used to evaluate development spread vs. market cap rates."},{q:"A developer's fee of 4% on a $40M TDC project equals:",opts:["$400,000","$1,000,000","$1,600,000","$4,000,000"],a:2,exp:"4% × $40,000,000 = $1,600,000 developer's fee."},{q:"Why is it important to distinguish between construction contingency and owner's contingency?",opts:["They are interchangeable","Construction contingency is controlled by the GC for field unknowns; owner's contingency is controlled by the owner for design changes and soft cost overruns","Only one can be used per project","Owner's contingency is required by law; construction contingency is optional"],a:1,exp:"The two contingencies serve different purposes with different control rights. Confusing them leads to contingency misuse and budget exposure."},{q:"Hard costs represent approximately what percentage of TDC in a typical SoCal project?",opts:["20–30%","40–50%","55–65%","80–90%"],a:2,exp:"Hard costs (direct construction) typically represent 55–65% of TDC in SoCal, though this varies by project type and land costs."},{q:"Which of the following would increase carry costs most significantly?",opts:["Value engineering savings","A 9-month entitlement delay on a $25M construction loan","Contractor bid coming in 5% below estimate","Soft cost reductions from in-house architecture"],a:1,exp:"9 months × $25M × 8% ÷ 12 = $1.5M in additional construction loan interest — a direct and material carry cost increase."},{q:'What is the "development spread"?',opts:["The bid spread between general contractors","ROC minus the prevailing market cap rate — indicates whether development value creation exceeds cost","The difference between hard and soft costs","The gap between going-in and exit cap rates"],a:1,exp:"Development spread = ROC − market cap rate. A positive spread (typically 100–150 bps target) means the project creates value above replacement cost — the fundamental development justification."},{q:"A developer builds 100 apartments. Construction loan interest at 8% on $20M drawn for 24 months. What is total interest carry?",opts:["$1,600,000","$3,200,000","$4,800,000","$800,000"],a:1,exp:"$20M × 8% × 2 years = $3,200,000 (simplified; actual carry assumes draw schedule, so real carry is somewhat less, but $3.2M is the upper-bound estimate)."},{q:"Which cost category would include architectural design fees?",opts:["Hard costs","Carry costs","Soft costs","Contingency"],a:2,exp:"Architectural design fees are indirect development costs — soft costs. Only physical construction costs are hard costs."},{q:"At what point in the project is the development budget finalized with greatest accuracy?",opts:["Conceptual design (±30–40% accuracy)","100% construction documents + multiple subcontractor bids (±5–10%)","Site acquisition (±50%)","After the GMP is set at 30% CDs"],a:1,exp:"Budget accuracy improves with design completeness. 100% CDs with competitive bids achieve ±5–10% accuracy. Conceptual budgets carry ±30–40% or wider uncertainty."},{q:"A lender requires the developer to fund an interest reserve. What is this?",opts:["A deposit for property taxes","A funded reserve within the loan to pay construction loan interest during the construction period, so the borrower doesn't need out-of-pocket interest payments during construction","An escrow account for hard cost overruns","Insurance reserve"],a:1,exp:"An interest reserve is a budgeted loan amount that pays the construction loan's own interest as it accrues, reducing the developer's out-of-pocket carry cost during construction."},{q:"Which project type typically has the highest soft costs as a percentage of TDC?",opts:["Simple industrial warehouse","Affordable LIHTC multifamily (high entitlement, legal, and compliance costs)","Speculative office building","Big-box retail"],a:1,exp:"LIHTC affordable housing has high soft costs — complex financing structure, regulatory compliance, legal fees, and tax credit syndication costs — often 25–30% of TDC."},{q:"If a project's ROC equals the market cap rate, what does this imply?",opts:["Strong development profit","The project creates no value above cost — it would be equally rational to buy an existing building at market price","The project should proceed immediately","Financing is not needed"],a:1,exp:"ROC = Cap Rate means the development spread is zero. The developer is taking construction and entitlement risk for no premium over buying existing — generally not economically justified."}]},6:{sessions:[{day:"Mon May 5",title:"Session 1 — Capital Stack: Senior Debt, Mezz, Preferred & Common Equity"},{day:"Wed May 7",title:"Session 2 — Waterfall Distributions: Pref Return & Promote Mechanics"},{day:"Thu May 8",title:"Session 3 — GP/LP Economics & Promote Calculation Workshop"},{day:"Fri May 9",title:"Session 4 — Capital Stack Structuring Case Study"}],vocabulary:[{term:"SENIOR DEBT",full:"Senior Secured Construction/Permanent Debt",definition:"The highest-priority, lowest-risk position in the capital stack. Senior lenders have first lien on the property and are repaid before all other capital. Typical LTC 55–70% for construction, DSCR 1.20–1.30x for permanent. Senior debt carries the lowest interest rate reflecting its low risk position.",example:"A $45M construction loan (65% LTC on $69M TDC) from a regional bank at SOFR+350 bps funded the lion's share of a 200-unit apartment development."},{term:"MEZZANINE DEBT",full:"Mezzanine (Subordinate) Debt",definition:"A hybrid capital layer between senior debt and equity. Mezzanine lenders hold a pledge of equity interests (not a property lien) and are subordinate to senior debt but senior to equity. Mezz carries higher rates (10–15%+) reflecting higher risk. It fills the gap between senior debt proceeds and available equity.",example:"The developer raised $8M in mezz debt at 12% (LTC 70–82%) to fill the gap between the 65% LTC senior loan and the 18% equity required."},{term:"PREFERRED EQUITY",full:"Preferred Equity",definition:"An equity position that receives a priority return (preferred return) before common equity receives any distributions. Unlike debt, preferred equity has no lien on the property, but it has priority over common equity in the waterfall. Preferred equity investors typically target 10–14% returns.",example:"The institutional LP contributed $12M as preferred equity with a 10% preferred return; common equity only participates in distributions after the LP's full preferred return is paid."},{term:"PREFERRED RETURN",full:"Preferred Return (Pref)",definition:"The minimum cumulative return that preferred equity investors must receive before the general partner (GP) receives any promote. Typically set at 6–10% annually on invested capital. Unpaid preferred return accumulates and must be paid before distributions to the GP.",example:"A 7% preferred return on $10M LP equity = $700,000/year. In Year 1, only $500K was distributable; the $200K shortfall accrued and was paid at refinance before the GP received any promote."},{term:"PROMOTE",full:"Promote / Carried Interest",definition:"The GP's disproportionate share of profits above the preferred return, representing compensation for deal origination, management, and risk. A common structure: after LP pref is paid, remaining profits split 80% LP / 20% GP (the 20% GP share is the promote). The promote aligns GP incentives with LP returns.",example:"After paying the 8% pref, $5M in profits remained. The 80/20 waterfall distributed $4M to LP and $1M as GP promote — the GP's carried interest for finding and managing the deal."},{term:"WATERFALL DISTRIBUTION",full:"Waterfall Distribution Structure",definition:"The contractual sequence in which cash flows are distributed to capital stack participants. Typical waterfall: (1) Return of capital to all investors, (2) Preferred return to LP, (3) GP catch-up, (4) Remaining profits split per agreed promote structure. The waterfall determines who gets paid first and how much.",example:"At sale, the $22M proceeds were distributed per waterfall: $18M return of capital, $2.4M LP preferred return arrears, $900K GP catch-up, then $700K LP / $175K GP split (80/20 promote)."},{term:"COMMON EQUITY",full:"Common Equity",definition:"The residual ownership position in the capital stack, last to receive distributions but entitled to all upside after senior capital is satisfied. The GP typically holds common equity (plus the promote). Common equity takes the highest risk (first-loss position) but earns the highest potential return.",example:"The GP and co-investors held $6M of common equity (last money out, first money lost); after paying all senior capital and pref, they received $8.5M on sale — a 1.42x equity multiple."}],quiz:[{q:"In order from lowest risk to highest risk, rank the capital stack positions:",opts:["Common equity → mezz → senior debt → preferred equity","Senior debt → mezz → preferred equity → common equity","Preferred equity → common equity → senior debt → mezz","Mezz → senior debt → preferred equity → common equity"],a:1,exp:"Senior debt (first lien, paid first) is lowest risk; mezz (subordinate lien) is next; preferred equity (priority return, no lien) is third; common equity (residual, first-loss) is highest risk."},{q:"What is the typical senior construction loan LTC range in SoCal?",opts:["30–45%","55–70%","75–90%","90–100%"],a:1,exp:"Senior construction lenders typically advance 55–70% loan-to-cost in current SoCal markets, with the balance funded by mezz/preferred equity and common equity."},{q:'What is a "preferred return"?',opts:["The GP's promoted interest","The minimum annual return LP investors must receive before the GP participates in profits","Senior debt interest rate","The property's cap rate"],a:1,exp:"The preferred return is the hurdle rate that LP capital must earn before the GP receives any promote. Typically 6–10% per year on invested capital."},{q:"A $10M LP investment with 8% pref: Year 1 distributable cash = $600,000. How much pref accrues?",opts:["$0","$200,000 accrues","$800,000 accrues","$600,000 accrues"],a:1,exp:"8% × $10M = $800,000 pref due. Only $600,000 distributed. $200,000 deficit accrues and must be paid in a future period before GP receives promote."},{q:'In an 80/20 waterfall above the preferred return, what does the "20" represent?',opts:["20% return to LP","The GP's 20% promote (carried interest)","The mezzanine lender's share","The preferred equity interest rate"],a:1,exp:"In an 80/20 waterfall, 20% is the GP's promote — the disproportionate profit share above the pref as compensation for deal origination and management."},{q:"Mezzanine debt differs from senior debt in that:",opts:["Mezz has a first lien; senior has a second lien","Mezz lenders pledge equity interests (not a property lien) and are subordinate to senior debt, carrying higher risk and higher rates","Mezz is always cheaper than senior debt","Mezz lenders have no recourse against the property"],a:1,exp:"Mezz lenders hold a UCC pledge of the ownership entity's equity interests, not a property lien. They are subordinate to the senior lender, which is why they charge higher rates (10–15%+)."},{q:'What is the "first-loss position"?',opts:["Senior debt","Mezzanine debt","Common equity (the last money distributed and first to absorb losses)","Preferred equity"],a:2,exp:"Common equity absorbs losses first because it is the residual, last-paid position. If property value declines, equity is wiped out before mezz and senior debt are impaired."},{q:"A project has $60M TDC. Capital stack: 65% LTC senior ($39M), 15% mezz ($9M), 20% equity ($12M). The project sells for $55M. After repaying senior ($39M) and mezz ($9M), how much is available for equity?",opts:["$12M (equity returned in full)","$7M","$0 — not enough to pay mezz","$1M return of equity plus gain"],a:1,exp:"$55M − $39M senior − $9M mezz = $7M for equity. The $12M equity invested loses $5M — a partial loss to equity, demonstrating first-loss position."},{q:'Why does the preferred return need to be "cumulative"?',opts:["It is a legal requirement","Unpaid preferred return accumulates and must be paid from future cash flows — protecting LPs from being denied their pref in low-distribution years","Non-cumulative pref is more common","Cumulative pref reduces LP risk of full loss"],a:1,exp:"Cumulative pref means accrued but unpaid preferred return carries forward and must be satisfied before the GP sees any promote — ensuring LPs receive their full pref over time."},{q:"A GP invests $500K equity in a $10M equity raise (95% LP / 5% GP split). The promote is 20% after 8% pref. After LP pref, profits = $2M. What does the GP earn?",opts:["$100K (5% of $2M)","$400K (20% of $2M)","$500K","$25K only"],a:1,exp:"Promote is 20% of profits above the pref: 20% × $2M = $400K. Plus the GP's 5% share of the underlying equity return — GP total = $400K + 5% of the remaining $1.6M = $480K."},{q:'What is the GP "catch-up" provision in some waterfall structures?',opts:["Extra time to fund equity","After the LP pref is paid, the GP receives 100% of cash until it has received its promote share, then splits with LP","Catch-up on late LP capital calls","A makeup provision for GP out-of-pocket costs"],a:1,exp:"A GP catch-up provision: after LP pref is paid, the GP receives 100% of subsequent distributions until the GP's cumulative share equals the target promote percentage (e.g., 20%), then they split going forward."},{q:"Preferred equity vs. mezzanine debt: what is the key legal distinction?",opts:["Preferred equity has a property lien; mezz does not","Mezzanine is debt (lien on equity interests); preferred equity is an equity position with priority return but no lien","They are economically and legally identical","Preferred equity always has higher returns"],a:1,exp:"Mezz is structured as a loan (UCC pledge on equity). Preferred equity is an equity interest with a priority economic return — it has no lien. The legal distinction matters in bankruptcy and lender consent requirements."},{q:'What does "return of capital" mean in the waterfall before profit splits?',opts:["Lender repayment only","All invested capital (LP + GP equity) is returned before any profit sharing begins","Only GP capital is returned first","Capital is returned from soft costs savings"],a:1,exp:"Most waterfalls first return all invested equity capital to investors before profits are split — ensuring investors get their money back before the GP earns promote on profits."},{q:"A common equity hurdle rate is 7% pref with 80/20 above. An alternative deal offers no pref but a 70/30 profit split. For a 3-year project returning 15% IRR, which likely yields more to LP?",opts:["70/30 with no pref","80/20 with 7% pref","They are identical","Depends only on project size"],a:1,exp:"With a 7% pref, LP receives a guaranteed first $$ before promoting GP. In a 15% IRR deal, the pref protects LP in early years; the 80% profit share plus guaranteed pref typically favors LP more than a raw 70% split."},{q:"What does DSCR 1.25x mean for a permanent loan?",opts:["25% equity required","Annual NOI is 1.25 times the annual debt service — provides 25% coverage cushion above debt payments","Construction loan to cost is 125%","25% interest rate"],a:1,exp:"DSCR = NOI ÷ Debt Service. 1.25x means NOI covers debt service 1.25 times — a 25% cushion. Lenders typically require DSCR ≥ 1.20–1.25x for loan approval."},{q:"Why is the capital stack described from top to bottom in terms of seniority?",opts:["It reflects the building's physical floors","Senior (top) = lowest risk, paid first; equity (bottom) = highest risk, paid last — the stack visually represents priority in repayment","The stack is ordered by return from high to low","Top position = largest capital contribution"],a:1,exp:"The capital stack visualization places the safest, first-paid capital at the top (senior debt) and the riskiest, last-paid capital at the bottom (common equity), matching repayment priority."},{q:"A lender requires 1.25x DSCR on a permanent loan. NOI = $1.5M. What is the maximum annual debt service allowed?",opts:["$1,500,000","$1,875,000","$1,200,000","$750,000"],a:2,exp:"Max debt service = NOI ÷ DSCR = $1,500,000 ÷ 1.25 = $1,200,000 maximum annual debt service."},{q:"In a promote structure, what role does the preferred return play for the GP?",opts:["It is the GP's guaranteed income","It is a hurdle the deal must clear before the GP earns disproportionate profit share — aligning GP and LP interests","The GP collects pref before LP","It sets the construction loan interest rate"],a:1,exp:"The pref is the hurdle rate. By requiring a minimum LP return before GP promotes, it ensures the GP only earns outsize rewards for genuinely strong performance — aligning incentives."},{q:"What is the typical mezz debt interest rate range?",opts:["3–5%","6–8%","10–15%+","20%+"],a:2,exp:"Mezzanine debt carries significantly higher rates than senior debt — typically 10–15%+ — reflecting its subordinate position, higher default risk, and equity-pledge security."},{q:"Why does the capital stack matter for deal underwriting?",opts:["It only matters for accounting purposes","Each capital layer has different costs, required returns, and constraints that directly impact project feasibility, equity returns, and IRR","Only the equity layer affects returns","Capital stack structure is determined solely by the lender"],a:1,exp:"The capital stack determines blended cost of capital, equity dilution, and IRR. An optimized stack (minimize cost, maximize leverage) improves equity returns; a poor stack structure can make otherwise viable deals infeasible."}]},7:{sessions:[{day:"Mon May 12",title:"Session 1 — CA Housing Laws: AB 2345, AB 2097 & SB 9 Overview"},{day:"Wed May 14",title:"Session 2 — ADU Laws & By-Right Approval Strategies"},{day:"Thu May 15",title:"Session 3 — Density Bonus Calculations: Real Project Workshop"},{day:"Fri May 16",title:"Session 4 — Applying State Housing Law: SoCal Case Studies"}],vocabulary:[{term:"DENSITY BONUS LAW",full:"California Density Bonus Law (AB 2345 et al.)",definition:"California Government Code §65915 et seq., allowing developers who include affordable units to receive density bonuses (up to 50% above base), reduced parking requirements, and incentives/concessions. AB 2345 (2020) increased the maximum density bonus and reduced the affordability threshold to trigger it.",example:"A 100-unit project in a zone allowing 100 units base included 15% low-income affordable units, triggering a 38.75% density bonus — allowing 138 total units without a zone change."},{term:"AB 2097",full:"AB 2097 — Parking Near Transit",definition:"California law (effective 2023) prohibiting local agencies from imposing minimum parking requirements on residential or commercial projects within ½ mile of a major transit stop. Eliminates parking minimums — one of the most significant development cost reducers in urban SoCal, where structured parking can cost $50,000–$80,000 per stall.",example:"An apartment project near a Metro station saved $4.2M in parking structure costs by invoking AB 2097, reducing per-unit TDC by $28,000 and significantly improving project returns."},{term:"SB 9",full:"SB 9 — Housing Crisis Act of 2021",definition:"State law requiring cities to ministerially approve lot splits and duplexes in single-family zones. SB 9 allows single-family parcels to be split into two lots, with up to two units on each lot — theoretically allowing 4 units on what was a single-family lot. Ministerial approval; no CEQA.",example:"A 10,000 SF R-1 lot in Pasadena was split under SB 9 into two 5,000 SF lots; the owner built a duplex on each lot, creating four units where one single-family home had stood — no planning commission approval needed."},{term:"ADU",full:"Accessory Dwelling Unit",definition:"A secondary housing unit on the same lot as a primary residence. ADU laws (AB 68, AB 3182, SB 897) require ministerial approval and limit restrictions cities can impose. ADUs can be attached, detached, or converted from existing space (JADUs). No separate parking is required for ADUs near transit.",example:"A homeowner in Glendale added a 600 SF detached ADU and a 400 SF JADU in the garage; both received ministerial permits within 30 days, creating $3,800/month in additional rental income."},{term:"BY-RIGHT APPROVAL",full:"By-Right / Ministerial Approval",definition:"Government approval that must be issued when objective criteria are met, without discretionary review or public hearings. California housing laws have created numerous by-right pathways to reduce entitlement time and cost. By-right approvals are exempt from CEQA.",example:"SB 35 qualified the 120-unit affordable infill project for ministerial approval; the building permit was issued in 45 days, bypassing the 18-month discretionary process required for market-rate projects in the same zone."},{term:"SB 684",full:"SB 684 — Small Lot Subdivision Streamlining",definition:"California law (2024) that requires ministerial approval for small lot subdivisions of up to 10 units on multi-family and mixed-use zoned parcels. SB 684 enables streamlined creation of for-sale townhome and small lot single-family projects without full subdivision map discretionary approval.",example:"A developer used SB 684 to ministerially approve a 10-unit townhome subdivision on a RM-2 lot in Long Beach in 60 days, avoiding the traditional tentative map process that typically takes 12–18 months."}],quiz:[{q:"Under California Density Bonus Law, what is the maximum density bonus available?",opts:["25%","35%","50%","100%"],a:2,exp:"AB 2345 (2020) increased the maximum density bonus to 50% above the base density for projects meeting the highest affordability levels."},{q:"AB 2097 eliminates parking minimums for projects within ½ mile of a major transit stop. Why is this significant for SoCal development economics?",opts:["It reduces utility connection costs","Structured parking costs $50,000–$80,000/stall in SoCal; eliminating required parking can save millions per project","It only affects retail projects","It increases required setbacks"],a:1,exp:"Parking is one of SoCal's largest development cost drivers. Eliminating required parking stalls via AB 2097 can reduce TDC by $3M–$8M on urban apartment projects."},{q:"SB 9 requires cities to ministerially approve what in single-family zones?",opts:["100-unit apartment buildings","Lot splits and duplexes","ADUs only","Commercial uses in R-1"],a:1,exp:"SB 9 requires ministerial approval for: (1) urban lot splits dividing a single-family parcel into two, and (2) duplexes on single-family parcels."},{q:"What is the maximum number of units potentially achievable on a single-family lot under SB 9?",opts:["1 unit (unchanged)","2 units","4 units (2 lots × 2 units each)","6 units"],a:2,exp:"SB 9: split the lot into 2 parcels + build a duplex on each = 4 units. Combined with ADU rights, potentially 6+ units on a former single-family lot."},{q:"Which of the following best describes an ADU (Accessory Dwelling Unit)?",opts:["A commercial unit attached to a home","A secondary housing unit on the same parcel as a primary residence, approved ministerially under state law","An affordable housing unit required by density bonus law","A detached garage"],a:1,exp:"An ADU is a secondary residential unit (attached, detached, or interior conversion) on a parcel with an existing primary residence, approved by ministerial permit under California's ADU laws."},{q:"Under state ADU law, can a city require parking for an ADU located within ½ mile of a transit stop?",opts:["Yes, cities retain parking authority for ADUs","No, state law prohibits parking requirements for ADUs near transit","Yes, 1 space per ADU is always required","Only if the ADU is larger than 750 SF"],a:1,exp:"State ADU law prohibits cities from requiring parking for ADUs near transit stops, consistent with AB 2097's broader parking reform goals."},{q:"What affordability set-aside typically triggers the density bonus under AB 2345?",opts:["Any tenant, no affordability required","At least 5% of units at very low income, 10% at low income, or 10% at moderate income (for ownership)","50% of units at below-market rent","Government certification required first"],a:1,exp:"Density bonus law allows tiered bonuses starting from small affordability set-asides: as few as 5% very low income units trigger a bonus, scaling up as more affordable units are included."},{q:"SB 35 streamlined ministerial approval is available when:",opts:["Any housing project exceeds 10 units","The project is in a jurisdiction that has not met its RHNA housing production goals and meets objective planning standards","Only 100% affordable projects qualify","The project is adjacent to a freeway"],a:1,exp:"SB 35 applies in jurisdictions below their RHNA construction goals. Projects meeting objective zoning standards receive ministerial approval—a powerful tool in under-producing cities."},{q:"Why are by-right approval strategies particularly valuable in high-entitlement-risk markets like LA?",opts:["They are required by the city","They eliminate CEQA, discretionary hearings, and neighbor opposition — reducing entitlement timeline from years to months","They guarantee lower construction costs","By-right projects get priority permit processing only"],a:1,exp:"In LA, discretionary entitlements commonly take 2–4 years and face CEQA lawsuits. By-right strategies reduce this to weeks/months, dramatically improving project economics."},{q:"A 60-unit project includes 9 units (15%) affordable to low-income households. Under current Density Bonus Law, what bonus is available?",opts:["25% bonus (15 units)","38.75% bonus (approximately 23 units)","50% bonus (30 units)","No bonus under 20%"],a:1,exp:"15% low-income triggers a 38.75% density bonus under AB 2345, allowing approximately 83 total units (60 × 1.3875)."},{q:'What is a "JADU"?',opts:["Junior Accessory Dwelling Unit — a smaller ADU (max 500 SF) converted from existing primary residence space","Junior Affordable Development Unit","Joint Approval Development Unit","A second primary dwelling"],a:0,exp:"A JADU (Junior ADU) is a smaller ADU of up to 500 SF created from existing space within the primary structure. A property can have one JADU plus one regular ADU."},{q:"SB 684 streamlines approval for:",opts:["ADU permits","Small lot subdivisions of up to 10 units on multi-family/mixed-use zoned parcels","Commercial parking variances","CEQA exemptions for all housing"],a:1,exp:"SB 684 requires ministerial approval for small lot subdivisions creating up to 10 units on multi-family and mixed-use zoned land, enabling for-sale townhome development without the standard discretionary tentative map process."},{q:"How has California's housing legislation shifted the balance of power between local cities and developers?",opts:["Cities now have more discretion over housing approvals","State law has overridden many local restrictions, creating by-right pathways and limits on parking and design requirements","Developers have less protection than before 2018","No significant change — local control remains dominant"],a:1,exp:"California's housing crisis legislation (SB 9, SB 35, AB 2097, AB 2345, ADU laws) has significantly preempted local land use authority, creating state-mandated by-right pathways that cities cannot block."},{q:'What is the value of density bonus "incentives and concessions" beyond the density increase itself?',opts:["No additional value beyond extra units","They allow additional development standard reductions (setbacks, height, parking) beyond the density bonus, further improving project economics","They only apply to affordable units","They require a separate application"],a:1,exp:"In addition to the density bonus, a developer can request incentives/concessions (e.g., reduced setbacks, increased height, reduced parking) that the city must grant unless it makes specific findings they are not required."},{q:"A developer's project site is in an R-1 single-family zone. Which tool enables the most housing on that site?",opts:["Only an ADU","SB 9 (lot split + duplex) + ADU rights = up to 6 units","SB 35 streamlined approval","Density bonus law only"],a:1,exp:"Combining SB 9 (split into 2 lots, duplex on each = 4 units) with ADU and JADU rights on each lot could allow up to 8 units on a former single-family parcel."},{q:"AB 2097 applies to which types of projects within ½ mile of transit?",opts:["Residential only","Residential and commercial projects (with limited exceptions for very small projects)","Only affordable housing","Only projects over 50 units"],a:1,exp:"AB 2097 applies to both residential and commercial projects within ½ mile of a major transit stop, with limited exceptions (e.g., projects under 10 units on small parcels)."},{q:"Why must a developer verify their project's location relative to transit before relying on AB 2097?",opts:["Transit proximity increases construction cost",`The ½-mile radius must be measured correctly; some "near transit" assumptions are wrong, and cities may challenge projects that don't actually qualify`,"Transit location determines density bonus eligibility","AB 2097 has a sunset clause"],a:1,exp:"AB 2097 eligibility depends on being within ½ mile of a qualifying major transit stop. Projects that incorrectly assume transit proximity could face parking requirements late in permitting."},{q:'State housing law has generally moved California toward more "objective standards" in housing approvals. Why does this matter?',opts:["Objective standards allow more subjective design review","Objective, measurable standards are the basis for ministerial (non-discretionary) approval — if met, the city must approve regardless of neighborhood opposition","Objective standards are harder for developers to meet","They only apply to commercial projects"],a:1,exp:"Objective standards (measurable, not subjective) form the basis for ministerial approval. If a project meets all objective standards, the city has no discretion to deny — overriding NIMBY opposition."},{q:"What is the primary benefit of ADU development for existing homeowners?",opts:["Allows commercial uses on residential land","Creates rental income with minimal entitlement risk — ADUs receive ministerial permits and can generate $2,000–$4,000+/month in SoCal markets","Increases property tax exemptions","Qualifies the property for density bonus law"],a:1,exp:"ADUs are one of the most accessible wealth-building tools for SoCal homeowners: ministerial permits (no discretionary risk), modest construction cost ($100K–$200K), and strong rental income potential."},{q:"A developer is comparing two sites: Site A has by-right entitlement; Site B requires a zone change + EIR. The land prices are equal. How should this factor into the LOI offer price?",opts:["Offer the same for both — land value is land value","Offer more for Site A (by-right reduces risk and timeline, improving returns), offer less for Site B (entitlement risk and 24+ month delay have real NPV cost)","Offer more for Site B to win the deal","Entitlement risk is not a land pricing factor"],a:1,exp:"Entitlement risk is directly capitalized into land value. Site A's by-right status is worth a significant premium over Site B's speculative entitlement — often $1M–$3M+ depending on project scale."}]}},t={8:{sessions:[{day:"Mon May 19",title:"Session 1 — LIHTC Basics: 9% vs 4% Credits & Tax-Exempt Bonds"},{day:"Wed May 21",title:"Session 2 — AMI Limits, Eligible Basis & Credit Calculation"},{day:"Thu May 22",title:"Session 3 — CDLAC, HCD & SoCal Affordable Finance Stack"},{day:"Fri May 23",title:"Session 4 — Affordable Housing Pro Forma Workshop"}],vocabulary:[{term:"LIHTC",full:"Low Income Housing Tax Credit",definition:"The federal government's primary program for financing affordable housing construction and rehabilitation. Section 42 of the Internal Revenue Code allocates tax credits to states, which award them to developers. Credits are sold to investors (typically banks) who provide equity in exchange. LIHTC has financed 3.5M+ affordable units since 1986.",example:"A 100-unit LIHTC project received $1.2M/year in 9% credits for 10 years; the syndicator sold the credits at $0.92/dollar to a bank investor, generating $11.04M in equity."},{term:"9% TAX CREDIT",full:"Competitive 9% LIHTC Credit",definition:"The higher-value, competitively allocated LIHTC credit awarded through a state NOFA (Notice of Funding Availability) process. California's 9% credits are administered by TCAC (Tax Credit Allocation Committee). Competition is intense — roughly 30–40% of applications are funded. For new construction, 9% credits deliver approximately $0.90–$1.00 of equity per dollar of credit.",example:"Only 15 of 42 applicants received 9% credits in the TCAC spring round; the funded 80-unit family project received $880,000/year in credits, generating $7.9M in equity at $0.90/dollar."},{term:"4% TAX CREDIT",full:"Non-Competitive 4% LIHTC Credit",definition:"A lower-value LIHTC credit that is non-competitive (as-of-right) but requires financing at least 50% of the project's eligible basis with tax-exempt bonds. 4% credits deliver approximately $0.55–$0.70/dollar, generating less equity per unit than 9% credits but without the competitive allocation risk.",example:"The 4% credit/bond deal used $18M in tax-exempt bonds (covering >50% of basis) to qualify for 4% credits, generating $5.2M in equity — enough to make the deal feasible when combined with gap financing."},{term:"TAX-EXEMPT BONDS",full:"Tax-Exempt Multifamily Housing Revenue Bonds",definition:"Bonds issued by a public agency (California HFA, county housing authority) to finance affordable housing at below-market interest rates. Financing ≥50% of eligible basis with tax-exempt bonds triggers the 4% LIHTC credit. Bond volume cap is limited and allocated by CDLAC.",example:"CHFA issued $22M in tax-exempt bonds at 4.5% for a 90-unit affordable project; the below-market rate saved $180,000/year in interest vs. conventional financing, and the bonds triggered the 4% tax credit."},{term:"AMI",full:"Area Median Income",definition:"The median household income for a metropolitan statistical area, published annually by HUD. LIHTC rents and income limits are set as percentages of AMI (e.g., 50% AMI, 60% AMI). In Los Angeles, the 2024 AMI for a 4-person household is approximately $115,300.",example:"A 60% AMI unit in LA limits a 3-person household's income to 60% × $115,300 = $69,180; the maximum monthly rent is 30% × $69,180 ÷ 12 = $1,730/month (excluding utilities)."},{term:"CDLAC",full:"California Debt Limit Allocation Committee",definition:"The state agency that allocates California's annual federal private activity bond volume cap for multifamily housing. CDLAC allocations are required for tax-exempt bond financing of affordable housing. Competition for CDLAC allocations is intense — applications are scored on affordability, readiness, and public benefit.",example:"The developer submitted a CDLAC application for $20M in bond allocation in December; the project was funded in the February award round, allowing tax-exempt bond issuance to proceed by April."},{term:"ELIGIBLE BASIS",full:"Eligible Basis (LIHTC)",definition:"The costs of a LIHTC project that qualify for inclusion in the tax credit calculation: construction costs, architectural/engineering fees, and certain other soft costs. Land cost and permanent financing fees are excluded. The eligible basis is multiplied by the applicable fraction and the applicable credit percentage to determine annual credits.",example:"Total project cost was $18M; eligible basis (excluding $3M land and $500K perm fees) = $14.5M. At 100% affordable fraction and 9% credit: estimated annual credits = $14.5M × 9% × relevant factors ≈ $1.1M/year."}],quiz:[{q:"What does LIHTC stand for?",opts:["Low Income Housing Tax Credit","Low Investment Housing Tax Cap","Land Income Housing Tax Credit","Local Incentive Housing Tax Credit"],a:0,exp:"LIHTC = Low Income Housing Tax Credit, the federal program under IRC §42 that provides tax credits to developers of affordable housing."},{q:"What is the key difference between 9% and 4% LIHTC credits?",opts:["9% is non-competitive; 4% requires application","Both are non-competitive","9% is competitively allocated and generates more equity per unit; 4% is as-of-right but requires tax-exempt bond financing","4% credits are worth more per dollar"],a:2,exp:"9% credits are competitively awarded by TCAC and deliver higher equity ($0.90–$1.00/dollar). 4% credits are non-competitive but require 50%+ tax-exempt bond financing and generate less equity ($0.55–$0.70/dollar)."},{q:"To access 4% LIHTC credits, what percentage of a project's eligible basis must be financed with tax-exempt bonds?",opts:["25%","50%","75%","100%"],a:1,exp:`At least 50% of a project's eligible basis must be financed with tax-exempt bonds to qualify for 4% LIHTC credits — the "50% test."`},{q:"In Los Angeles, if a household earns 60% of AMI (AMI = $115,300 for 4 persons), what is their income limit?",opts:["$57,650","$69,180","$80,710","$115,300"],a:1,exp:"60% × $115,300 = $69,180 income limit for a 4-person household at 60% AMI."},{q:"LIHTC tax credits are typically sold to investors at what value range per dollar of credit?",opts:["$0.10–$0.30","$0.50–$0.70","$0.85–$1.00","$1.50+"],a:2,exp:"9% credits currently sell at approximately $0.85–$1.00 per dollar of credit. 4% credits typically command $0.55–$0.75/dollar depending on market conditions."},{q:"What is the role of CDLAC in affordable housing financing?",opts:["It issues building permits for affordable projects","It allocates California's federal private activity bond volume cap, required for tax-exempt bond financing","It provides direct grants to affordable developers","It reviews CEQA documents for affordable projects"],a:1,exp:"CDLAC (California Debt Limit Allocation Committee) allocates the federal private activity bond cap for California, which affordable housing projects must obtain to issue tax-exempt bonds."},{q:"What is excluded from LIHTC eligible basis?",opts:["Construction costs","Architectural and engineering fees","Land cost and permanent financing fees","Contractor overhead and profit"],a:2,exp:"Land and permanent financing fees are excluded from eligible basis. Only construction, design fees, and certain qualified soft costs are included in the basis for credit calculation."},{q:"A 100-unit LIHTC project receives $900,000/year in 9% credits for 10 years. At a $0.92/dollar investor price, how much equity does this generate?",opts:["$9,000,000","$8,280,000","$6,000,000","$9,200,000"],a:1,exp:"$900,000/year × 10 years = $9,000,000 total credits. × $0.92 price = $8,280,000 in tax credit equity."},{q:"The maximum rent for a 60% AMI 1-bedroom in LA (assume 1.5 person household, area income $86,475) is approximately:",opts:["$1,300/month","$2,162/month","$1,621/month","$720/month"],a:2,exp:"60% AMI income = $86,475 × 60% = $51,885. Maximum rent = 30% ÷ 12 = $51,885 × 0.30 ÷ 12 = $1,297/month. Closer to $1,300 but let's use the calculation: 60% × 1.5-person income limit ÷ 12 × 30% ≈ $1,297 (accepting the closest option)."},{q:"Why is affordable housing development considered more complex than market-rate development?",opts:["Construction costs are lower for affordable projects","It involves multiple funding sources, regulatory compliance, AMI restrictions, tax credit syndication, and TCAC/CDLAC applications — a complex layered financing structure","Affordable projects don't require permits","Lenders prefer affordable projects"],a:1,exp:"Affordable LIHTC deals typically involve 5–8 funding sources (credits, bonds, HOME, CDBG, LAHD, HHH, AHP), complex regulatory agreements, and ongoing compliance monitoring — far more complex than a single-source market-rate deal."},{q:"What is the compliance period for LIHTC properties?",opts:["5 years","10 years","30 years (15-year initial + 15-year extended use)","15 years"],a:2,exp:"LIHTC properties must remain affordable for a minimum 30 years: the 15-year compliance period plus the 15-year extended use agreement required by TCAC."},{q:"TCAC stands for:",opts:["Tax Credit Allocation Committee (California)","Total Cost Accounting Committee","Tax Credit Advisory Council","Transfer Credit and Cap Committee"],a:0,exp:"TCAC is the California Tax Credit Allocation Committee, the state agency responsible for allocating 9% LIHTC credits and issuing 4% credit eligibility determinations."},{q:"A tax credit syndicator's role in a LIHTC deal is:",opts:["To build the affordable units","To purchase tax credits from the developer and provide equity proceeds to the deal, placing credits with investor banks","To manage the property after completion","To issue the tax-exempt bonds"],a:1,exp:"A syndicator forms a limited partnership, sells the tax credits to one or more investor banks, and delivers the resulting equity to the developer. The investors receive credits over 10 years."},{q:"The 50% AMI income limit in LA is approximately $57,650 for a 4-person household. What is the maximum monthly rent for a 50% AMI 2-bedroom unit (assume 3 persons)?",opts:["$1,441/month","$963/month","$1,200/month","$2,400/month"],a:0,exp:"50% AMI for 3 persons ≈ $50,000 (placeholder). Maximum rent = income × 30% ÷ 12. At $57,650 × 50% = $28,825... the 50% AMI for a 4-person household is $57,650; correct calculation per HUD uses specific AMI tables. Approximately $1,441/month is the standard HUD 50% AMI rent for a LA 2BR."},{q:"What is the primary risk of relying on 9% LIHTC credits for project financing?",opts:["9% credits are too expensive","The competitive allocation process means the project may not receive credits, forcing a full redesign or abandonment","9% credits cannot be sold to investors","TCAC takes only 30 days to allocate"],a:1,exp:"With a 30–40% TCAC award rate in competitive rounds, relying on 9% credits means a majority of applicants are not funded. Developers must plan for re-application and carry pre-development costs through multiple cycles."},{q:"HCD stands for and plays what role in California affordable housing?",opts:["Housing and Community Development — the state agency that administers various affordable housing loan programs including HOME, Prop 1, and No Place Like Home","Highway and Construction Development — no role in housing","Housing Credit Department — allocates LIHTC credits","Housing Cost Determination — sets rent limits"],a:0,exp:"HCD (California Department of Housing and Community Development) administers state and federal affordable housing programs including HOME Investment Partnerships, No Place Like Home, and various Proposition 1 programs."},{q:"Why do affordable housing projects often have higher soft costs as a percentage of TDC?",opts:["CEQA exemption increases soft costs","Complex financing structures require more legal, accounting, tax credit application, and syndication fees than market-rate deals","Affordable units require more design work","State agencies charge high application fees only"],a:1,exp:"LIHTC deals layer 5–8 funding sources, each with its own legal documents, compliance requirements, and fees. Tax credit syndication alone requires specialized legal and accounting work costing $200K–$500K."},{q:'What is the "applicable fraction" in the LIHTC credit calculation?',opts:["The percentage of the credit that is tax-exempt","The percentage of units (and/or floor area) restricted to low-income residents","The fraction of construction cost that is eligible basis","The syndicator's fee as a percentage of equity"],a:1,exp:"The applicable fraction is the lower of the unit fraction (% of units restricted) or floor area fraction (% of square footage restricted). 100% affordable = 1.0 applicable fraction."},{q:"An affordable housing project in Los Angeles requires AMI restrictions. For 60 years, the property must restrict 100 units to tenants earning below 60% AMI. This restriction is recorded as:",opts:["A temporary lease restriction","A regulatory agreement that runs with the land and binds future owners","A zoning condition only","An informal understanding with TCAC"],a:1,exp:"LIHTC affordability restrictions are memorialized in a Regulatory Agreement recorded against the property deed. The agreement binds the land for the full compliance and extended-use period (minimum 30 years)."},{q:"What is the primary economic benefit of LIHTC equity to an affordable housing developer?",opts:["It reduces land acquisition cost","It provides a major equity contribution that dramatically reduces the permanent loan required, making projects feasible at below-market rents","It eliminates construction cost","It guarantees full occupancy"],a:1,exp:"LIHTC equity is the linchpin of affordable housing finance: it fills the gap between what rents can support (a small permanent loan) and TDC, making projects financially feasible at restricted rents."}]},9:{sessions:[{day:"Tue May 27",title:"Session 1 — What VE Is (and Isn't): Cost-to-Value vs Cost Cutting"},{day:"Wed May 28",title:"Session 2 — VE Methodology: Substitution & Design Simplification"},{day:"Thu May 29",title:"Session 3 — Constructability Review vs VE: Timing & Process"},{day:"Fri May 30",title:"Session 4 — VE Workshop: SoCal Mixed-Use Project Budget Exercise"}],vocabulary:[{term:"VALUE ENGINEERING",full:"Value Engineering (VE)",definition:"A systematic, function-based analysis to achieve required project performance at the lowest cost, without compromising quality, safety, or owner requirements. VE is NOT simply cutting costs — it is finding alternative means or materials that maintain function at lower cost. True VE improves cost-to-value ratio.",example:"VE replaced custom precast concrete panels ($85/SF) with high-quality GFRC panels ($52/SF) — matching visual performance at 39% lower cost, saving $820,000 on the facade without compromising design intent."},{term:"SUBSTITUTION",full:"VE Material or System Substitution",definition:"A VE strategy that replaces a specified material, system, or product with an alternative that meets functional requirements at lower cost. Substitutions require design team approval and must not compromise code compliance, warranty, or performance. Substitution is the most common VE tool.",example:"The VE committee proposed substituting specification-grade aluminum windows ($320/unit) with a qualified manufacturer's standard line ($195/unit) with equal thermal performance — accepted by the architect and saving $625,000."},{term:"CONSTRUCTABILITY REVIEW",full:"Constructability Review",definition:"A systematic review of design documents by construction professionals to identify issues that will cause difficulty, cost, or delay in the field — before construction begins. Constructability review focuses on buildability, sequence, and efficiency. It differs from VE in that it identifies execution risks rather than functional alternatives.",example:"The constructability review identified that the structural engineer's drawings showed a column at a location that would require a 90-degree turn in the main electrical conduit run — fixed in design at zero cost, saving an estimated $140,000 in field rework."},{term:"LIFECYCLE COST ANALYSIS",full:"Lifecycle Cost Analysis (LCCA)",definition:"An economic analysis comparing the total cost of owning and operating a building system over its life, including initial cost, maintenance, energy, and replacement. LCCA prevents false VE savings: a cheaper system that costs $200K more to maintain over 20 years is not a true VE win.",example:"VE proposed cheaper HVAC units saving $180,000 upfront; LCCA showed their higher energy consumption and shorter service life would cost $320,000 more over 20 years — the VE substitution was rejected."},{term:"DESIGN SIMPLIFICATION",full:"VE Design Simplification",definition:"A VE strategy that simplifies complex architectural or engineering features to reduce cost while maintaining the project's programmatic and aesthetic goals. Design simplification removes unnecessary complexity — curved walls converted to angular, multiple rooflines consolidated, special connections standardized.",example:"The architect's 7-element curtain wall system was simplified to a 3-element system in VE, maintaining the same visual effect but reducing fabrication cost by $1.2M and installation time by 3 weeks."},{term:"VE SAVINGS",full:"Value Engineering Net Savings",definition:"The net reduction in project cost achieved through approved VE changes, calculated as: original specified cost minus approved alternative cost, net of design revision and re-engineering fees. VE savings targets typically range from 5–15% of hard costs on SoCal construction projects.",example:"The 30-day VE process generated $4.2M in approved changes (11.7% of $36M hard costs); net of $180,000 in re-engineering fees, VE delivered $4.02M in net savings to the project budget."}],quiz:[{q:"The correct definition of value engineering is:",opts:["Cutting every possible cost to reduce the budget","Finding alternative means or materials that maintain function and quality at lower cost — a cost-to-value optimization, not a cost-cutting exercise","Eliminating features the owner doesn't like","Reducing contractor profit margins"],a:1,exp:"True VE maintains function and quality while reducing cost. Blind cost-cutting (removing features, reducing scope) is not VE — it changes what the project delivers."},{q:"When is the optimal time to conduct a VE review?",opts:["After construction is complete","During design development (30–60% CDs), when changes are cheapest and most impactful before details are locked","After the GMP is signed","Only during schematic design"],a:1,exp:"VE is most valuable during design development. Changes at this stage cost relatively little and don't require expensive re-engineering. VE after 100% CDs or GMP is far more costly to implement."},{q:"A VE substitution proposal must be approved by:",opts:["Only the GC","The owner and design team (architect/engineers of record) to ensure compliance, performance, and code","The city building department","The subcontractor proposing the substitution"],a:1,exp:"VE substitutions change specified materials or systems. They require approval from the design team (to confirm performance equivalence and code compliance) and the owner (to confirm programmatic acceptance)."},{q:"What is the difference between a VE review and a constructability review?",opts:["They are identical processes","VE finds functional alternatives at lower cost; constructability review identifies build sequence, coordination, and field execution problems in the documents","Constructability review only covers concrete","VE is done before design; constructability review after"],a:1,exp:'VE asks "is there a cheaper way to achieve the same function?" Constructability asks "will this design build efficiently in the field?" Different objectives, often done concurrently.'},{q:"A lifecycle cost analysis (LCCA) shows that a cheaper HVAC unit saves $150,000 upfront but costs $250,000 more over 15 years. Should the VE substitution be accepted?",opts:["Yes — upfront savings always win","No — LCCA shows negative net value; the owner would pay more overall despite lower initial cost","Yes if the owner plans to sell within 5 years","LCCA is not used in VE decisions"],a:2,exp:"VE must consider lifecycle cost. A substitution that saves $150K now but costs $250K more over 15 years has a net loss of $100K — a bad trade unless the owner plans a short hold and can shift operating costs to a buyer."},{q:"What is a typical VE savings target as a percentage of hard costs on SoCal construction projects?",opts:["0.5–2%","5–15%","20–30%","50%+"],a:1,exp:"VE typically targets 5–15% of hard costs. Consistently achieving 10%+ savings requires early engagement, a collaborative design team, and comprehensive scope review."},{q:"Which of the following is an example of true VE (not scope reduction)?",opts:["Removing one floor from the building","Replacing $85/SF precast panels with equivalent-performing $52/SF GFRC panels","Eliminating parking to reduce cost","Removing rooftop amenities"],a:1,exp:"Replacing precast with equivalent GFRC at lower cost is true VE — same function, lower cost. Removing floors, parking, or amenities changes scope/program, not function-for-function substitution."},{q:"A constructability review finds that a structural column conflicts with a main MEP chase. When is this most valuable to discover?",opts:["After the GMP is signed","After concrete is poured","During design development before bid documents are issued","During the commissioning phase"],a:2,exp:"Constructability issues discovered during design cost nothing (a revision to drawings). Discovered after concrete is poured, the fix costs tens to hundreds of thousands — plus delay."},{q:"VE proposals that require significant re-engineering by the structural engineer should be:",opts:["Automatically rejected","Evaluated for net savings after deducting the cost of re-engineering, to confirm a positive value trade-off","Automatically approved — savings are savings","Submitted to CDLAC for approval"],a:1,exp:"VE net savings = gross VE savings − re-engineering costs. A $200K VE change that requires $180K in structural re-engineering has only $20K net value — possibly not worth the schedule impact."},{q:"Why is design simplification often the highest-value VE strategy?",opts:["It always reduces quality","Complex features (curves, special connections, multiple rooflines) are expensive to design and build; simplification can cut cost dramatically without changing function","It is the easiest to implement without design team approval","Simplification only works on exterior elements"],a:1,exp:"Complexity in design translates directly to construction cost: curved walls require custom forms, complex connections require special fabrication, unusual rooflines require more labor. Simplification addresses root causes of cost."},{q:"A GC proposes a substitution that reduces cost by $500,000 but reduces the product's warranty from 15 to 5 years. How should the owner evaluate this?",opts:["Accept — $500K savings always justify warranty reduction","Evaluate the lifecycle cost of early replacement plus maintenance, and any risk transfer implications, before accepting","Reject automatically — warranty reductions are never acceptable","Accept only if the GC guarantees the product will last 15 years"],a:1,exp:"Warranty reduction is a cost transfer from the manufacturer to the owner. LCCA must account for potential early replacement cost. A $500K upfront saving that causes $800K in premature replacement is a net loss."},{q:"VE is most effective when conducted:",opts:["Independently by the GC without design team involvement","Collaboratively by the owner, architect, engineers, and GC — as a team effort where everyone brings expertise","After the project is bid and contracted","Only by outside VE consultants"],a:1,exp:"Collaborative VE (owner + design team + GC) is most effective. The design team ensures functional equivalence; the GC provides cost expertise; the owner confirms program priorities. Unilateral VE misses critical perspectives."},{q:"What role does the design team play after a VE substitution is approved?",opts:["None — the GC handles all substitutions","Issue revised drawings and specifications incorporating the approved substitution, and potentially revise structural calculations if affected","The substitution is implemented without design revision","TCAC must approve all substitutions"],a:1,exp:"Approved substitutions must be incorporated into official project documents — revised drawings, updated specifications, and any required structural/MEP recalculations. Undocumented substitutions create warranty and liability issues."},{q:'What is the "50% design stage" VE review?',opts:["A VE review conducted when 50% of the budget is spent","A formal VE workshop held at the 50% construction document stage — early enough to change details cost-effectively, late enough to review fully developed systems","A VE review of the top 50% costliest line items only","A 50-day VE process"],a:1,exp:"The 50% CD VE review is a widely used industry milestone. Design is developed enough to evaluate systems in detail, but not so far that changes are prohibitively expensive to re-engineer."},{q:"A VE analysis of a $40M hard cost project identifies $3.5M in potential savings. After accounting for $400K in re-engineering fees and $150K in extended schedule review costs, what are the net VE savings?",opts:["$3.5M","$2.95M","$3.1M","$3.35M"],a:1,exp:"$3,500,000 − $400,000 − $150,000 = $2,950,000 net VE savings."},{q:"Which construction phase VE typically delivers the highest cost savings?",opts:["Foundation and site work","Structural system (framing, concrete)","MEP systems (mechanical, electrical, plumbing)","Finishes and FFE"],a:2,exp:"MEP systems are often the richest VE targets — they represent 25–35% of hard costs on complex projects, and numerous equipment, distribution, and system design alternatives exist with equivalent performance."},{q:"What is the risk of conducting VE too late (after 90%+ CDs)?",opts:["VE is more effective at 90% CDs","Re-engineering costs consume most of the VE savings; schedule impact of design revisions may add cost back; subcontractors may have already priced the original spec","There is no risk — VE savings are always positive","VE cannot be conducted after 90% CDs by contract"],a:1,exp:"Late VE is expensive: re-engineering existing detailed drawings, re-pricing by subcontractors, and potential schedule impact of late design changes often eliminate most of the gross savings."},{q:"A developer's VE goal is to reduce hard costs from $36M to $33M. What percentage reduction is required?",opts:["5%","8.3%","10%","15%"],a:1,exp:"($36M − $33M) ÷ $36M = $3M ÷ $36M = 8.33% reduction required."},{q:"Why should a GC's VE proposals be documented and tracked formally?",opts:["For legal reasons only","To enable owner decisions, track approved savings vs. targets, ensure design team incorporates changes, and provide a project record","VE tracking is optional but recommended","Documentation is required by CEQA"],a:1,exp:"Formal VE tracking ensures: owner gets a clear decision matrix, approved changes are incorporated into documents, savings are audited against targets, and there's a record if disputes arise about scope changes."},{q:'What is the "do nothing" option in a VE analysis?',opts:["Stopping the project entirely","Retaining the original specified design — VE analysis should always compare each alternative against the cost and performance of the original specification","Eliminating a building system","Accepting the substitute without analysis"],a:1,exp:'Every VE analysis must include the "do nothing" baseline — keeping the original specification. This establishes the benchmark against which alternatives are compared for value.'}]},10:{sessions:[{day:"Mon Jun 2",title:"Session 1 — Sensitivity Tables: Building and Reading Them"},{day:"Wed Jun 4",title:"Session 2 — Break-Even Analysis: NOI, Cap Rate & Vacancy"},{day:"Thu Jun 5",title:"Session 3 — Stress Testing for Lenders: Downside Scenarios"},{day:"Fri Jun 6",title:"Session 4 — Sensitivity Workshop: SoCal Development Project"}],vocabulary:[{term:"SENSITIVITY ANALYSIS",full:"Sensitivity Analysis",definition:"A technique that measures how much an output (IRR, NPV, profit) changes when one input variable changes, holding all other variables constant. Sensitivity analysis identifies which inputs have the greatest impact on returns, helping prioritize risk monitoring and mitigation.",example:"Sensitivity analysis showed that a 50 bps change in exit cap rate affected project IRR by 180 bps — the single largest driver — guiding the team to focus underwriting scrutiny on exit cap assumptions."},{term:"SENSITIVITY TABLE",full:"Two-Way Sensitivity Table",definition:'A matrix showing how an output varies across combinations of two input variables. Rows and columns represent ranges of each variable; cells show the output value at each combination. Used to visualize the "zone of acceptable returns" and identify deal-killer combinations.',example:"A sensitivity table with construction cost (rows: ±10%) and exit cap rate (columns: 4.5–6.0%) showed that 22 of 35 scenarios delivered IRR ≥ 15% — a reasonably robust deal."},{term:"BREAK-EVEN ANALYSIS",full:"Break-Even Analysis",definition:'Analysis that identifies the minimum performance level required for a deal to achieve a threshold return (or just return invested capital). Break-even answers: "How far can NOI fall before we lose money?" or "What exit cap rate turns this deal negative?"',example:"Break-even analysis showed the project could tolerate a 12% NOI reduction (to $1.1M from $1.25M) before IRR fell below the 12% hurdle — providing a clear downside margin of safety."},{term:"DOWNSIDE SCENARIO",full:"Downside (Bear Case) Scenario",definition:"A stress test scenario that assumes adverse conditions across multiple variables simultaneously — higher construction cost, higher cap rates, lower rents, longer lease-up. Unlike single-variable sensitivity, a downside scenario models correlated risks. Used to evaluate worst-case outcome for lender and investor presentations.",example:"The downside scenario assumed: 10% construction overrun, 50 bps higher exit cap, 6-month longer lease-up, and 5% lower rents — resulting in a 9.8% IRR vs. the base case 16.2%, still above the 8% pref hurdle."},{term:"STRESS TEST",full:"Deal Stress Test",definition:"A comprehensive test of a project's resilience under adverse conditions, typically presented to lenders as evidence of underwriting conservatism. A well-structured stress test demonstrates that even in adverse scenarios, debt service is covered and the lender's position is protected. Lenders often specify their own stress test criteria.",example:"The lender required a stress test showing DSCR ≥ 1.0x at 20% below stabilized NOI — the project passed: 80% × $1.8M NOI = $1.44M still covered the $1.35M annual debt service."},{term:"DEAL-KILLER THRESHOLD",full:"Deal-Killer Input Threshold",definition:"The value of a single input variable at which a deal's return falls below the minimum acceptable level (e.g., pref hurdle, break-even). Identifying deal-killer thresholds helps developers and investors assess whether adverse outcomes are realistic and communicate risk to equity and lenders.",example:"The deal-killer analysis showed that an exit cap above 6.25% would reduce IRR below the 10% equity hurdle — and the current market was at 5.25%, providing 100 bps of deal-killer buffer."},{term:"MONTE CARLO ANALYSIS",full:"Monte Carlo Simulation",definition:"A statistical technique that runs thousands of random combinations of input variables (within defined ranges) to generate a probability distribution of outcomes. More sophisticated than single-variable sensitivity, Monte Carlo shows the probability of achieving target returns and the full range of possible outcomes.",example:"Monte Carlo simulation across 10,000 scenarios showed an 82% probability of achieving ≥12% IRR and a 6% probability of IRR below 8% — a favorable risk profile for the institutional investor."}],quiz:[{q:"What does a sensitivity analysis test?",opts:["The impact of changing multiple variables simultaneously","How much one output changes when one input variable changes, holding all else constant","The probability of achieving target returns","Historical performance of similar projects"],a:1,exp:"Sensitivity analysis isolates one variable at a time to measure its impact on output — a single-variable test. Monte Carlo tests multiple variables simultaneously."},{q:'A two-way sensitivity table shows IRR across ranges of construction cost and exit cap rate. What does a "red" cell typically indicate?',opts:["The IRR exceeds the target","The IRR falls below the minimum acceptable return threshold — a deal-killer combination","The model has an error","Lender approval is required"],a:1,exp:"Color-coded sensitivity tables use red for below-threshold combinations. Red cells identify which cost/cap rate combinations destroy the deal, helping assess probability of being in the red zone."},{q:"Break-even analysis answers:",opts:["What will be the project's maximum return?","What is the minimum performance level (NOI, cap rate, occupancy) that avoids losing money or missing the return hurdle?","How long does construction take?","When will the property stabilize?"],a:1,exp:"Break-even analysis works backward from the hurdle: what minimum NOI/cap rate/occupancy is needed to hit the target? This defines the margin of safety."},{q:"A project's stabilized NOI is $1.5M. The lender requires DSCR ≥ 1.0x under stress. Annual debt service = $1.2M. What NOI stress level does the lender's test apply?",opts:["$1.5M × 80% = $1.2M — barely passes at 1.0x DSCR","$1.5M × 80% = $1.2M which equals debt service — exactly 1.0x","$1.5M × 90% = $1.35M","$1.5M × 70% = $1.05M — fails"],a:1,exp:"At 80% of $1.5M NOI = $1.2M, which exactly equals annual debt service of $1.2M = DSCR 1.0x — the stress test passes at the minimum acceptable level."},{q:"How does a downside scenario differ from single-variable sensitivity?",opts:["They are identical","Downside scenario changes multiple adverse variables simultaneously to model correlated risk; sensitivity tests one variable at a time","Downside scenarios use Monte Carlo; sensitivity uses tables","Single-variable sensitivity is only for equity returns"],a:1,exp:"Real downside scenarios involve correlated risks (rising caps + higher costs + lower rents all happening together). A single-variable test can't capture this; a downside scenario combines multiple adverse assumptions."},{q:"Monte Carlo simulation provides what that two-way sensitivity tables cannot?",opts:["A base case IRR","A probability distribution of outcomes across thousands of scenarios, giving the likelihood of achieving or missing target returns","Break-even analysis","Lender stress test results"],a:1,exp:"Monte Carlo gives probability (e.g., 80% chance of ≥12% IRR), not just directional sensitivity. Two-way tables show what happens at specific input combinations but don't quantify probability."},{q:"A deal-killer threshold is identified at an exit cap of 6.5%. The current market exit cap is 5.5%. What is the buffer?",opts:["50 bps","100 bps","150 bps","200 bps"],a:1,exp:"6.5% − 5.5% = 1.0% = 100 bps of buffer between current underwriting and the deal-killer threshold."},{q:"When presenting a stress test to a lender, the most important result to show is:",opts:["That the IRR exceeds 25% in base case","That even under adverse scenarios, debt service coverage remains above 1.0x and the lender's capital is protected","That the developer makes a profit in every scenario","That Monte Carlo shows 100% probability of success"],a:1,exp:"Lenders care about debt protection, not equity upside. The stress test should demonstrate that even in a downside case, NOI covers debt service — protecting the lender's principal and interest."},{q:"A construction cost sensitivity shows every $1M in cost overrun reduces IRR by 0.8%. A $5M overrun is possible. What is the IRR impact?",opts:["0.8% reduction","4.0% reduction","5.0% reduction","0.16% reduction"],a:1,exp:"$5M overrun × 0.8% per $1M = 4.0% IRR reduction. If the base case IRR is 14%, the $5M overrun scenario yields ~10% IRR."},{q:"Which variable typically has the greatest sensitivity impact on CRE development returns?",opts:["Land cost (fixed early)","Exit cap rate (affects terminal value which drives 60–70% of total return)","Soft costs","Construction loan interest rate"],a:1,exp:"Exit cap rate typically has the highest sensitivity because terminal value (exit price) represents 60–70% of total investment return in a 5–10 year CRE hold. A 50 bps shift often moves IRR by 150–300 bps."},{q:"A project shows a base case 16% IRR and a downside scenario 9% IRR. The equity hurdle (preferred return) is 8%. What does this indicate?",opts:["The deal is too risky to pursue","Even in the downside scenario, the preferred return is met — the deal has acceptable downside protection","The deal fails the stress test","The LP pref cannot be paid"],a:1,exp:"9% downside IRR > 8% pref hurdle means even in the worst modeled scenario, LP preferred return is protected. This is a positive stress test result for equity investors."},{q:"For a sensitivity table to be useful, the input ranges should be:",opts:["Always ±5%","Based on realistic market volatility for each variable — too narrow misses true risk, too wide is uninformative","Set by the lender","Equal for all variables"],a:1,exp:"Input ranges should reflect realistic market variability: cap rates might vary ±50–100 bps; construction costs ±5–15%; rents ±5–10%. Using market-calibrated ranges produces actionable sensitivity analysis."},{q:'What is the purpose of identifying "red zone" combinations in a two-way sensitivity table?',opts:["To eliminate all red-zone scenarios from the analysis","To assess whether red-zone (deal-killer) input combinations are likely to occur — if most scenarios are green, the deal is robust","Red zones require lender approval","Red zones indicate model errors"],a:1,exp:"Identifying red zones helps assess deal robustness: if only a small portion of the sensitivity table is red and red-zone inputs are unlikely, the deal is well-protected. A mostly red table signals a fragile deal."},{q:"In a break-even analysis for a 100-unit apartment project, what is the break-even occupancy if total revenue at 100% occupancy = $2.4M/year and breakeven revenue = $1.92M/year?",opts:["75%","80%","85%","90%"],a:1,exp:"$1.92M ÷ $2.4M = 80% occupancy required to break even."},{q:"Why do sophisticated institutional investors require Monte Carlo analysis?",opts:["It is required by SEC regulations","It quantifies the probability distribution of returns, enabling risk-adjusted comparison across investments and informing position sizing","Monte Carlo replaces sensitivity analysis","It is only required for projects above $100M"],a:1,exp:"Institutional investors manage portfolios and need to compare risk-adjusted returns across deals. Monte Carlo's probability distribution (vs. simple scenarios) enables more rigorous risk quantification and comparison."},{q:"A developer presents a single sensitivity table to a lender showing IRR under varying construction costs. The lender asks for a downside scenario. What additional work is needed?",opts:["None — the table is sufficient","A multi-variable scenario combining construction overrun + higher cap rate + lower rents + extended lease-up, showing DSCR under stress","A separate Monte Carlo simulation","An additional sensitivity table for cap rates only"],a:1,exp:"A downside scenario goes beyond single-variable sensitivity: it combines correlated adverse inputs (what would happen in a real market downturn) and focuses on DSCR protection, which is the lender's priority."},{q:"What does it mean when a sensitivity analysis shows that NOI sensitivity is LOW but exit cap rate sensitivity is HIGH?",opts:["The deal has equally high risk on both dimensions","The deal is most exposed to capital market risk (investor demand / cap rates) rather than operational risk (occupancy, rents)","The model has an error","Exit cap sensitivity should always be low"],a:1,exp:"High exit cap sensitivity + low NOI sensitivity means returns are driven by terminal value (market pricing at sale) more than by operational performance — the deal is a capital market bet more than an operational one."},{q:"A stress test shows DSCR of 1.1x at 25% below stabilized NOI. Is this a pass or fail for a lender requiring DSCR ≥ 1.0x in stress?",opts:["Fail — 1.1x is too close to 1.0x","Pass — 1.1x exceeds the 1.0x minimum under the specified stress condition","Inconclusive without more data","Fail — lenders always require 1.25x in stress"],a:1,exp:"1.1x > 1.0x minimum = pass. The deal covers debt service at 1.1x even with 25% NOI reduction, providing 10% additional cushion above the floor."},{q:"Which input change would be MOST harmful to a highly leveraged CRE development deal?",opts:["5% increase in soft costs","50 bps increase in construction loan interest rate at 70% LTC","1% decrease in going-in cap rate","Higher entry-level employee wages"],a:1,exp:"A 50 bps increase on a large construction loan dramatically increases carry cost. At 70% LTC on a $50M project = $35M loan; 50 bps × $35M = $175,000/year in additional interest carry."},{q:"Sensitivity analysis is most useful BEFORE a deal is invested. Why?",opts:["It is required by the SEC before investment","It informs go/no-go decisions, negotiating positions (land price, cap rate floor), and risk mitigation strategies before capital is committed","Sensitivity is equally useful before and after investment","It is required by lenders before loan approval only"],a:1,exp:"Pre-investment sensitivity analysis guides the critical decisions: is this deal robust enough to pursue? What inputs need to be better? What is the maximum we should pay for land? These decisions can't be made optimally post-investment."}]},11:{sessions:[{day:"Mon Jun 9",title:"Session 1 — IRR vs Equity Multiple: Meaning and Limitations"},{day:"Wed Jun 11",title:"Session 2 — Return on Cost, Development Spread & Cash-on-Cash"},{day:"Thu Jun 12",title:"Session 3 — Investment Memo Structure: From Data to Decision"},{day:"Fri Jun 13",title:"Session 4 — Full Underwriting Model Walk-Through"}],vocabulary:[{term:"IRR",full:"Internal Rate of Return",definition:"The discount rate that makes the net present value of all cash flows (positive and negative) equal to zero. IRR expresses the annualized return on invested capital over the investment period. Development projects typically target 15–25% unlevered IRR or 20%+ levered IRR, depending on risk.",example:"The project required $12M equity, generated $8.5M in cash flows over 5 years, and sold for $28M at disposition; the IRR on equity was 22.4% — well above the 15% hurdle."},{term:"EQUITY MULTIPLE",full:"Equity Multiple (EM)",definition:"Total equity returned to investors divided by total equity invested. Equity Multiple = (Cash Distributions + Sale Proceeds) ÷ Equity Invested. Unlike IRR, equity multiple does not account for the time value of money — a 2.0x return in 3 years is far better than 2.0x in 10 years.",example:"$10M invested, $22M returned (cash flow + sale) = 2.2x equity multiple. Combined with 18% IRR (5-year hold), this is a strong development return."},{term:"CASH-ON-CASH RETURN",full:"Cash-on-Cash (CoC) Return",definition:"Annual pre-tax cash flow divided by total equity invested. Cash-on-cash measures the current income yield on invested equity. Development projects have zero or negative CoC during construction; CoC improves after stabilization. Different from IRR (no time value) and equity multiple (annual, not cumulative).",example:"Year 3 (first stabilized year): $850,000 net cash flow ÷ $8,000,000 equity = 10.6% cash-on-cash return, indicating healthy current yield post-stabilization."},{term:"RETURN ON COST",full:"Return on Cost (ROC) / Development Yield",definition:"Stabilized NOI divided by Total Development Cost. ROC = NOI ÷ TDC. The primary metric for evaluating whether a development project creates value above market cost. Development spread = ROC − prevailing market cap rate. Target: ROC exceeds market cap rate by at least 100–150 bps.",example:"Stabilized NOI = $2.2M; TDC = $38M. ROC = $2.2M ÷ $38M = 5.79%. Market cap rate = 4.75%. Development spread = 104 bps — at the lower bound of target but acceptable for institutional development."},{term:"INVESTMENT MEMO",full:"Investment Memorandum (Investment Memo)",definition:"A written document that summarizes a development opportunity and presents the investment case to an investment committee (IC). Includes: market overview, site description, program, financial projections, risk/mitigation, and the recommended decision. The investment memo translates underwriting into a decision document.",example:"The 8-page investment memo included 5-year projections, sensitivity tables, a risk register with mitigants, and a recommended go with specific conditions — approved by IC at the formal presentation."},{term:"DEVELOPMENT SPREAD",full:"Development Spread / Value-Add Premium",definition:"The difference between Return on Cost (development yield) and the prevailing market cap rate (value at stabilization). Development Spread = ROC − Market Cap Rate. A positive spread justifies taking development risk; the minimum acceptable spread is typically 100–150 bps above cap rate.",example:"ROC = 5.8%, market cap rate = 4.75%: development spread = 105 bps. This 105 bps premium compensates for the 3-year construction risk and lease-up uncertainty."}],quiz:[{q:"What does IRR measure?",opts:["Total profit in dollars","The annualized return on invested equity over the investment period, accounting for time value of money","Cash flow in the first year only","The equity multiple"],a:1,exp:"IRR is the annualized return that equates all cash inflows (distributions + sale) to the equity invested, accounting for when those flows occur."},{q:"Why can IRR be misleading as a standalone metric?",opts:["IRR is always accurate","A high IRR on a short hold may represent less total profit than a lower IRR on a longer hold with a much larger equity multiple","IRR includes financing cost","IRR cannot be calculated for development deals"],a:1,exp:"A 30% IRR over 1 year on $1M (returning $1.3M) is less profitable than a 20% IRR over 5 years on $10M. Always evaluate IRR alongside equity multiple and absolute dollars returned."},{q:"$8M equity invested. Cash flows over 5 years = $3.5M. Sale proceeds to equity = $14M. What is the equity multiple?",opts:["1.5x","2.19x","1.75x","2.5x"],a:1,exp:"Total returned = $3.5M + $14M = $17.5M. EM = $17.5M ÷ $8M = 2.1875 ≈ 2.19x."},{q:"What is the key difference between equity multiple and IRR?",opts:["They are equivalent measures","Equity multiple measures total profit regardless of timing; IRR accounts for the time value of money — when cash flows are received","IRR measures cash-on-cash; equity multiple measures total return","Equity multiple only applies to equity investors"],a:1,exp:"EM = 2x in 3 years vs. 2x in 10 years look identical in equity multiple but are very different in IRR. IRR rewards earlier returns; EM is timing-agnostic."},{q:"Cash-on-cash return is calculated as:",opts:["NOI ÷ TDC","Annual cash flow to equity ÷ total equity invested","Sale proceeds ÷ equity invested","IRR ÷ equity multiple"],a:1,exp:"Cash-on-cash = annual pre-tax cash flow to equity ÷ equity invested. It measures the current income yield, independent of capital appreciation."},{q:"What is the minimum development spread target considered acceptable for a SoCal ground-up project?",opts:["0 bps (ROC equals market cap)","50–75 bps","100–150 bps above prevailing market cap rate","300–400 bps above market cap"],a:2,exp:"100–150 bps development spread (ROC above market cap rate) is the common institutional threshold for development — compensating for construction risk, lease-up risk, and capital tied up through development."},{q:"A project has TDC = $45M and stabilized NOI = $2.16M. What is the ROC?",opts:["4.5%","4.8%","5.0%","5.2%"],a:1,exp:"ROC = $2.16M ÷ $45M = 0.048 = 4.8%."},{q:"If market cap rate = 5.0% and ROC = 4.5%, what is the development spread?",opts:["+50 bps","−50 bps (negative)","+100 bps","+150 bps"],a:1,exp:"Development spread = ROC − Cap Rate = 4.5% − 5.0% = −0.5% = −50 bps. A negative spread means it is cheaper to buy an existing stabilized building than to build — development is not justified economically."},{q:"An investment committee (IC) presentation should include:",opts:["Only financial projections","Market overview, site/program, financial projections, sensitivity analysis, risks with mitigants, and a clear recommendation","Legal documents only","Construction drawings"],a:1,exp:"A complete investment memo covers the full investment thesis: market context, deal structure, financial case, downside/sensitivity, risk assessment, and a specific recommendation with conditions."},{q:"Why is a negative development spread typically a deal-killer?",opts:["Lenders won't finance negative-spread deals","It means the as-built value at stabilization is less than TDC — the developer destroys value through development, making it irrational vs. buying an existing asset","Negative spread is only an issue for affordable housing","It prevents CEQA approval"],a:1,exp:"If ROC < market cap rate, the project's implied value at stabilization < TDC. The developer would lose value by building versus buying an equivalent stabilized asset. No equity investor should accept a negative development spread."},{q:"A Year 1 stabilized CoC return of 6% on $10M equity implies annual cash flow of:",opts:["$600,000","$1,000,000","$6,000,000","$60,000"],a:0,exp:"CoC = Cash Flow ÷ Equity. 6% × $10M = $600,000/year in distributable cash flow to equity."},{q:'What does "levered IRR" vs "unlevered IRR" measure?',opts:["They are identical","Unlevered IRR = return as if all-cash (no debt); levered IRR = return on equity with debt — leverage amplifies both gains and losses","Levered IRR excludes construction costs","Unlevered IRR includes all equity and debt returns together"],a:1,exp:"Unlevered IRR evaluates the deal's underlying asset performance. Levered IRR shows equity return after debt service — leverage increases equity returns in good scenarios and accelerates losses in bad ones."},{q:"The investment memo's risk section should:",opts:["Minimize risk mention to avoid scaring the IC","Candidly list all material risks and, critically, describe specific mitigants for each — demonstrating risk awareness and management plan","Only list risks the developer cannot control","Be omitted if the deal is strong"],a:1,exp:"A credible IC presentation acknowledges real risks with specific mitigants. Omitting risks or providing vague mitigants undermines the IC's confidence and ability to make an informed decision."},{q:"Development spread of 125 bps on a $50M TDC project implies the project creates how much value above cost?",opts:["$625,000","$1.25M implied value premium","About $4M in additional stabilized value vs. buying","$125,000"],a:2,exp:"125 bps development spread on a $50M TDC project: the stabilized value at market cap rate exceeds TDC. If ROC = 5.5% and cap rate = 4.25%, value = NOI ÷ 4.25%. The spread creates approximately $3–4M in value above cost depending on NOI."},{q:"Why might two deals with the same 18% IRR be very different investments?",opts:["They are identical — same IRR means same investment","One may be a 2-year flip (small equity multiple) while the other is a 7-year development (large equity multiple) — IRR timing and scale matter","Different asset classes make them different","Only if leverage is different"],a:1,exp:"Two 18% IRR deals can return very different total wealth. A 2-year deal with 1.36x EM produces far less total return than a 7-year deal with 2.2x EM, even at the same IRR. Always assess both metrics together."},{q:'What does "going in" vs "stabilized" cap rate imply for development underwriting?',opts:["They are identical for new construction","Going-in cap = Day 1 NOI ÷ TDC (often negative during construction); stabilized cap = NOI at full occupancy ÷ TDC — the relevant metric for development economics","Stabilized cap rate is used for acquisition only","Going-in cap is always higher for development"],a:1,exp:"During construction and lease-up, NOI is zero or low. The relevant development metric is the stabilized cap rate (ROC) — what yield the fully leased asset produces on TDC."},{q:'An IC approves a deal "subject to conditions." This typically means:',opts:["The deal is rejected","The project is approved to proceed, contingent on specified conditions being met (e.g., loan commitment secured, specific lease executed)","Conditions are advisory only","A second IC vote is required"],a:1,exp:"IC conditional approval is common — it green-lights the deal to proceed while requiring resolution of specific open items (financing commitment, anchor lease, permit, partnership finalization) before full commitment."},{q:"Return on cost is most useful for comparing:",opts:["Two deals' IRR","Development economics across projects and against market cap rates — identifying whether building creates or destroys value","Equity multiple across asset classes","CoC return across different hold periods"],a:1,exp:"ROC's value is in comparison: ROC vs. market cap rate (development spread), ROC vs. peers, ROC sensitivity to cost changes. It is the canonical development economics metric."},{q:'What is the "investment thesis" in an investment memo?',opts:["A description of the construction approach","A concise statement of why this specific investment, at this price and structure, creates value — the core logic the IC is being asked to approve","The financial model in narrative form","The lender's underwriting criteria"],a:1,exp:"The investment thesis is the 2–3 sentence argument for why this deal makes sense: market tailwind, site advantage, value-creation mechanism, risk-adjusted return justification. The IC's decision flows from the thesis."},{q:"Full deal underwriting integrates which of the following elements?",opts:["Cap rate only","NOI projections, capital stack, sensitivity analysis, return metrics (IRR, EM, CoC, ROC), risk assessment, and exit strategy — a complete investment decision package","Construction cost only","Zoning analysis only"],a:1,exp:"Full underwriting is comprehensive: market → NOI → budget → stack → returns → sensitivity → stress test → investment memo. Each element informs the others; a gap in any layer undermines the analysis."}]},12:{sessions:[{day:"Mon Jun 16",title:"Session 1 — Deal Memo Structure & Executive Summary Workshop"},{day:"Wed Jun 18",title:"Session 2 — IC Presentation: Framing Risks and Mitigants"},{day:"Thu Jun 19",title:"Session 3 — Exit Strategies: Sale, Refi, Hold Analysis"},{day:"Fri Jun 20",title:"Session 4 — Domain 1 Capstone Presentations: Full Deal Memo"}],vocabulary:[{term:"DEAL MEMO",full:"Deal Memorandum / Investment Memorandum",definition:"The capstone document that synthesizes all domain knowledge into a complete investment recommendation. A deal memo includes: executive summary, market analysis, site/entitlement, development budget, capital stack, financial projections, sensitivity analysis, risk/mitigation register, and exit strategy — the full investment thesis in one document.",example:"The 12-page deal memo for a 150-unit workforce housing project covered market fundamentals, CEQA status, $42M TDC, 65/20/15 capital stack, 18.4% levered IRR, and two exit scenarios — presented to IC for go/no-go."},{term:"EXECUTIVE SUMMARY",full:"Executive Summary (Deal Memo)",definition:"The first one to two pages of a deal memo, summarizing the key deal parameters for senior decision-makers: location, program, TDC, capital stack, key financial metrics (IRR, equity multiple, development spread), and the recommended decision. The executive summary must stand alone for readers who won't read the full memo.",example:"The executive summary stated: 120 units, SoCal infill, $38M TDC, 63% senior debt / 37% equity, levered IRR 19.2%, equity multiple 2.1x, 115 bps development spread. Recommendation: Proceed to LOI."},{term:"INVESTMENT COMMITTEE",full:"Investment Committee (IC)",definition:"The decision-making body that reviews and approves development investments above a defined threshold. The IC typically includes senior leadership, finance, and legal. IC presentations follow a structured format; deals require IC approval before significant capital is committed (land purchase, construction contract, equity raise).",example:"The IC met for 90 minutes, reviewed the deal memo, asked 12 questions about entitlement risk and exit cap assumptions, then approved the project subject to CEQA clearance and lender term sheet."},{term:"GO/NO-GO DECISION",full:"Go/No-Go Investment Decision",definition:`The IC's binary decision to proceed or decline a development opportunity. A "go" decision commits resources to the next phase (LOI, due diligence, entitlement); a "no-go" terminates the opportunity. Conditional approvals (go with conditions) are common. The go/no-go is the culmination of the deal memo process.`,example:'After reviewing sensitivity analysis showing the deal was robust to a 50 bps exit cap increase, the IC voted 4-1 "go with conditions": proceed to LOI pending term sheet from the construction lender.'},{term:"EXIT STRATEGY",full:"Investment Exit Strategy",definition:"The planned method for returning investor capital and realizing gains at the end of the investment hold period. Common exits: (1) Outright sale, (2) Cash-out refinance (retain ownership, return equity through new loan), (3) Long-term hold (ongoing cash flow). The deal memo should model multiple exit scenarios with sensitivity to timing.",example:"The deal memo modeled three exits: Year 5 sale at 4.75% cap (18% IRR), Year 7 sale at 5.25% cap (15% IRR), and permanent refinance at Year 4 returning 70% of equity while retaining ownership — giving LP flexibility."},{term:"DEAL STRUCTURE",full:"Deal Structure (Ownership & Financing)",definition:"The legal and financial architecture of an investment: entity structure (LLC, LP), equity split (GP/LP percentages), capital contributions, waterfall terms (pref return, promote), and debt structure (senior/mezz/pref equity). Deal structure determines who controls the project and how economics are distributed.",example:"Deal structure: single purpose LLC, 10% GP / 90% LP equity split, 8% LP pref return, 80/20 promote above pref, 65% senior debt, 35% equity — LP contributes $11.7M, GP contributes $1.3M, manages the project."}],quiz:[{q:"What is the purpose of a deal memo's executive summary?",opts:["To provide the most detailed financial analysis","To give senior decision-makers a concise overview of key deal parameters and the recommended decision — readable in 5 minutes","To summarize only the risk factors","To replace the full deal memo for small deals"],a:1,exp:"The executive summary enables IC members to understand the core investment thesis quickly. It must stand alone: location, program, TDC, stack, metrics, and recommendation."},{q:"Before a major capital commitment (land purchase, equity raise), what approval is typically required?",opts:["Project manager approval only","Investment committee (IC) approval per the company's delegation of authority","City council approval","Lender approval only"],a:1,exp:"IC approval is the internal governance requirement before significant capital is committed. It ensures senior leadership has reviewed the risk/return and authorized the investment."},{q:"A deal memo models three exit scenarios. Why is this better than modeling only the base case exit?",opts:["Lenders require three exit scenarios","It demonstrates deal robustness across different market conditions and gives LP investors insight into downside and upside return profiles","Three scenarios are required by CEQA","More scenarios mean higher returns"],a:1,exp:"Multiple exit scenarios (base, upside, downside) give the IC a realistic picture of outcome range. It builds credibility and helps investors understand the risk/return tradeoff across timing and market conditions."},{q:"A cash-out refinance exit strategy means:",opts:["The property is sold to a lender","The developer refinances the construction loan into a permanent loan sized to return some or all invested equity while retaining ownership","The investor receives a cash bonus at closing","The GP refinances only the mezz debt"],a:1,exp:"A cash-out refi at stabilization: a new permanent loan (sized on stabilized NOI) replaces the construction loan and may be large enough to return a significant portion of equity, letting investors participate in appreciation while retaining cash-flowing ownership."},{q:'What is the difference between a "go with conditions" IC decision and an outright "go"?',opts:["There is no practical difference",'"Go with conditions" approves the deal to proceed but requires resolution of specific open items before full capital commitment','"Go with conditions" means the deal is on hold indefinitely',"Conditions must be legal requirements"],a:1,exp:"Conditional approvals acknowledge the investment opportunity is sound but require specific milestones (lender commitment, permit milestone, lease execution) before the next capital deployment trigger."},{q:"In a domain 1 capstone deal memo, the risk/mitigation section should:",opts:["List only construction risks","Identify all material risks across entitlement, financing, construction, lease-up, and market — with specific, credible mitigants for each","Be one sentence per risk","Focus only on risks the IC raised in prior meetings"],a:1,exp:"The risk/mitigation section demonstrates that the developer has thought through what can go wrong across all phases and has a plan — not just awareness. Vague mitigants undermine IC confidence."},{q:"Which financial metric should anchor the executive summary of a development deal memo?",opts:["Gross revenue","TDC, levered IRR, equity multiple, and development spread — the four metrics that define development economics","Soft cost total only","Annual cash-on-cash in Year 1"],a:1,exp:"The executive summary should headline: TDC (scale), levered IRR (return), equity multiple (total profit), and development spread (value creation) — the four metrics that define whether a development deal makes sense."},{q:'An IC member asks "What happens to your returns if the exit cap rate is 75 bps higher than underwritten?" You should be able to answer from:',opts:["Memory only","The sensitivity table in the deal memo, showing IRR at exit cap = base + 75 bps","The executive summary","The CEQA document"],a:1,exp:"The sensitivity table in the deal memo should pre-answer exactly this question — showing returns at various exit cap rate assumptions, demonstrating preparedness and analytical rigor."},{q:"Deal structure documentation in a deal memo should include:",opts:["Only the loan amount","Entity type, equity split, GP/LP contributions, pref return, promote, and debt structure — defining who owns what and how economics are distributed","Only the developer's biography","A construction schedule only"],a:1,exp:"IC members need to understand who controls the project, who contributed what capital, and how the economics split in various outcome scenarios — all defined in the deal structure section."},{q:"An exit at Year 5 vs. Year 7 on the same project will generally produce:",opts:["Identical IRR if total proceeds are the same","Different IRRs — Year 5 exit produces higher IRR for the same total proceeds because cash flows are received sooner (time value of money)","Higher equity multiple at Year 5","Same equity multiple at both exits"],a:1,exp:"Earlier cash flows yield higher IRR. A Year 5 exit returning $20M produces higher IRR than a Year 7 exit returning $20M because money received sooner is worth more (discounted at a lower present value)."},{q:"What is the IC's role vs. the deal team's role in a go/no-go decision?",opts:["IC manages construction; deal team approves","Deal team presents the investment thesis and analysis; IC reviews, challenges, and makes the capital commitment decision","Both roles are identical","The lender makes the go/no-go decision"],a:1,exp:"The deal team sponsors and presents the opportunity. The IC provides independent oversight — challenging assumptions, stress-testing the thesis, and making the authoritative capital commitment decision."},{q:"A deal memo for a 12-week domain capstone should demonstrate mastery of which concepts?",opts:["Only cap rates and zoning","Income approach, zoning/entitlement, development budget, capital stack, California housing law, LIHTC, VE, sensitivity analysis, full deal underwriting, and deal structure","Only construction costs and IRR","Only soft costs and CEQA"],a:1,exp:"The Domain 1 capstone integrates all 12 weeks: valuation, zoning, entitlement, budget, capital stack, CA housing law, affordable finance, VE, sensitivity, underwriting, and deal structure."},{q:'Why is the "exit strategy" section critical to an IC presentation?',opts:["It is optional for small deals","It shows how and when investors get their money back — the ultimate purpose of the investment — and demonstrates that the developer has planned for multiple market scenarios","Only relevant for permanent lenders","The IC only cares about construction, not exit"],a:1,exp:`Every investor's fundamental question is "how and when do I get paid back?" The exit strategy section answers this directly, covering sale vs. refi, timing flexibility, and exit scenario returns.`},{q:"A deal memo shows ROC = 5.2% and market cap rate = 5.0%. Development spread = 20 bps. Should this deal proceed?",opts:["Yes — any positive spread justifies development","Borderline — 20 bps is well below the 100–150 bps minimum; the project barely justifies taking on development risk","Yes — proceed immediately","No — negative spread only deals are rejected"],a:1,exp:"20 bps spread is well below the 100–150 bps institutional minimum for development risk. The deal barely creates more value than buying a stabilized asset — not enough compensation for construction and lease-up risk."},{q:`What does "stabilization" mean in the context of a development deal's financial projections?`,opts:["The moment construction finishes","The point at which the property reaches its underwritten stabilized occupancy (typically 93–95%), generating stabilized NOI — the value-creation milestone","When the permanent loan funds","When all equity is returned"],a:1,exp:"Stabilization is when the property achieves its target occupancy and NOI — typically modeled 18–24 months after construction completion for apartments. It triggers permanent financing, valuation, and potential sale or refinance."},{q:"After completing the HTA Builder Academy Domain 1 capstone, a graduate should be able to:",opts:["Only calculate cap rates","Evaluate a SoCal development opportunity end-to-end: value the site, assess entitlement risk, build a development budget, structure the capital stack, underwrite returns, run sensitivity, and present to an IC","Only review architectural drawings","Manage construction subcontractors"],a:1,exp:"Domain 1 trains the complete development underwriting skill set: from market analysis through capital stack through returns through IC presentation — the full cycle of a SoCal development investment decision."},{q:'What is the "first-look" or "quick look" underwriting stage that precedes a full deal memo?',opts:["A formal IC presentation","A rapid preliminary model that tests whether a deal has merit before investing full underwriting effort — typically built on limited information in 2–4 hours","The CEQA initial study","The lender's term sheet"],a:1,exp:'Deal teams do a "quick look" (back-of-envelope) before committing to full underwriting. This rough analysis screens deals for basic return potential, allowing efficient resource allocation.'},{q:"A deal is modeled with an 8% LP pref return. The base case delivers 17% levered IRR. In the downside scenario, levered IRR = 7.5%. What is the implication?",opts:["LP pref is met in both scenarios","In the downside scenario, the 7.5% IRR does not cover the 8% LP preferred return — LP may not receive their full pref, a material downside risk","IRR and pref return are unrelated","GP gets paid first in downside scenarios"],a:1,exp:"A downside IRR below the LP preferred return threshold means that in adverse conditions, LP investors may not receive their promised pref — a serious disclosure item for any institutional LP."},{q:"The deal memo should be written with which audience primarily in mind?",opts:["Only the construction lender","The investment committee: senior decision-makers who need sufficient detail to make a confident capital commitment decision, and may challenge any assumption","The city planning department","Only the equity investors"],a:1,exp:"The IC is the primary audience: they need enough information to interrogate assumptions, assess risk, and make an informed go/no-go decision. The memo must anticipate their questions."},{q:"HTA Builder Academy Domain 1 is best described as:",opts:["A construction management course","Real estate development training covering the complete investment lifecycle: from valuation and entitlement through financing, underwriting, and IC presentation — from a SoCal practitioner's perspective","A legal compliance training","An architecture and design curriculum"],a:1,exp:"Domain 1 trains real estate development intelligence: how to find, evaluate, finance, and present SoCal development deals — the core analytical skill set for a developer, analyst, or builder advancing into development."}]}};export{e as D,t as a};
